import type { Drill } from "./types";

// Finance / early drills, keyed by module slug — 25 per module.
// Pitched at a financial analyst / junior accountant: variance explanations,
// close status updates, data requests, model walkthroughs, flagging
// discrepancies, summarizing numbers for non-finance readers. Merged into course.ts.
export const FINANCE_EARLY_DRILLS: Record<string, Drill[]> = {
  "lead-with-the-point": [
    {"id":"lead-fin-early-01","level":"early","profession":"finance","title":"The buried variance headline","scenario":"Your manager asked why marketing is over budget this month. You know the answer — a $40K campaign that was planned for next quarter ran early — but your draft email opens with three sentences about how you pulled the data.","task":"Write a 2-3 sentence reply that states the cause in the first sentence.","tips":["Sentence one: the driver and the dollar amount.","How you found it is support, not the headline.","Your manager should be able to forward sentence one as-is."],"focus":["structure","clarity"],"placeholder":"Marketing is $40K over because the spring campaign ran in March instead of Q2 —"},
    {"id":"lead-fin-early-02","level":"early","profession":"finance","title":"The close status nobody can find","scenario":"It's day 3 of month-end close. Everything is on track except one bank reconciliation waiting on a statement. Your status message to the finance channel starts with a list of every task you completed since Monday.","task":"Write a 1-2 sentence status update that leads with the overall state of the close.","tips":["First words: on track, at risk, or blocked.","Name the one open item and what it's waiting on.","The completed-task list can live in a thread reply."],"focus":["concision","structure"],"placeholder":"Close is on track for day 5 — one open item:"},
    {"id":"lead-fin-early-03","level":"early","profession":"finance","title":"The receipt chase that rambles","scenario":"The operations manager owes you receipts for six corporate-card transactions before you can post their expenses. Your draft opens with an apology for bothering them and a paragraph about the close calendar.","task":"Write a message that puts the ask and the deadline in the first sentence.","tips":["Lead with what you need and by when.","Cut the apology — this is their obligation, asked politely.","Attach or list the six transactions so they can act immediately."],"focus":["clarity","impact"],"placeholder":"I need receipts for 6 card transactions by Thursday to post your expenses —"},
    {"id":"lead-fin-early-04","level":"early","profession":"finance","title":"The duplicate payment discovery","scenario":"While reconciling accounts payable you found the same $8,200 vendor invoice paid twice, once in February and once in March. Your draft to your manager walks through the whole reconciliation before naming the problem.","task":"Write a 2-3 sentence message that leads with the finding and the amount.","tips":["First sentence: what happened and how much.","Then the fix you propose — request a credit or refund.","The reconciliation trail is evidence for later, not the opener."],"focus":["clarity","impact"],"placeholder":"We paid vendor invoice #4471 ($8,200) twice —"},
    {"id":"lead-fin-early-05","level":"early","profession":"finance","title":"The forecast question, answered last","scenario":"Your manager asks in Slack: \"Are we still on track to hit the Q2 revenue forecast?\" You know the answer is yes, with one product line slightly soft. Your instinct is to walk through every line before saying so.","task":"Write a reply that answers yes or no in the first three words, then adds the one caveat.","tips":["Answer the question asked before explaining anything.","One caveat, one sentence — not a full walkthrough.","Offer detail on request rather than by default."],"focus":["concision","clarity"],"placeholder":"Yes — on track, with one soft spot:"},
    {"id":"lead-fin-early-06","level":"early","profession":"finance","title":"The audit request reply","scenario":"The external auditors asked for twelve supporting documents. You have ten ready and two will take until Friday. Your draft reply describes your filing system before saying what's attached.","task":"Write a 2-3 sentence reply that leads with what's attached now and when the rest arrives.","tips":["First sentence: 10 of 12 attached, remaining 2 by Friday.","Name the two outstanding items so there's no ambiguity.","Auditors track completeness — give them the count up front."],"focus":["structure","precision"]},
    {"id":"lead-fin-early-07","level":"early","profession":"finance","title":"The reconciliation gap","scenario":"The inventory account is off by $3,150 between the sub-ledger and the general ledger, and you've traced it to a missed journal entry. Your message to your manager starts with the history of the account.","task":"Write a message that names the gap, the cause, and the fix in the first two sentences.","tips":["Lead with the amount and the account.","Cause and proposed correcting entry come immediately after.","Save the tracing narrative for the backup file."],"focus":["clarity","structure"],"placeholder":"Inventory is off by $3,150 — a missed entry from the 3/14 shipment."},
    {"id":"lead-fin-early-08","level":"early","profession":"finance","title":"The model is done — say so","scenario":"You spent two weeks building the headcount cost model your manager asked for. The answer it produces: the new team costs $612K in year one. Your draft email describes every tab before stating that number.","task":"Write a 2-3 sentence email that leads with the answer the model produces.","tips":["The output is the headline; the model is the machinery.","State the number, then one sentence on what drives it.","Link the file instead of describing its structure."],"focus":["structure","impact"],"placeholder":"The new team costs $612K in year one —"},
    {"id":"lead-fin-early-09","level":"early","profession":"finance","title":"The budget-submission chase","scenario":"Three department heads still haven't submitted their budget templates, and the consolidation is due to the controller Monday. Your reminder email opens with a recap of the whole budget process.","task":"Write a reminder that puts the deadline and the specific ask in sentence one.","tips":["Lead with: templates due to me by Friday noon.","Say what happens if they miss it — their numbers get estimated.","One sentence of context is plenty; they know the process."],"focus":["clarity","impact"]},
    {"id":"lead-fin-early-10","level":"early","profession":"finance","title":"The accrual question you're sitting on","scenario":"You're unsure whether to accrue a $15K consulting invoice that arrived after cutoff, and you need your manager's call today to close on time. Your draft explains accrual policy for two paragraphs before asking.","task":"Write a message that puts the decision you need in the first sentence.","tips":["Lead with the question: accrue the $15K invoice or push to next month?","Give the one fact that matters for the call — services were delivered in March.","Name the deadline for the decision."],"focus":["clarity","concision"],"placeholder":"Quick call needed by 3pm: do we accrue the $15K consulting invoice?"},
    {"id":"lead-fin-early-11","level":"early","profession":"finance","title":"The report that will be late","scenario":"The monthly department spending report you owe the operations director will be a day late because the ERP data feed failed overnight. Your draft opens with a technical explanation of the feed.","task":"Write a 2-sentence message that states the new delivery time first.","tips":["Lead with the new time: tomorrow by noon.","One clause on why is enough — data feed failure, being rerun.","Don't make them read the outage story to learn the date."],"focus":["clarity","concision"],"placeholder":"The spending report will land tomorrow by noon instead of today —"},
    {"id":"lead-fin-early-12","level":"early","profession":"finance","title":"The correction you have to send","scenario":"Yesterday's flash report overstated April revenue by $92K because a credit memo was missed. The corrected number changes the month from ahead-of-plan to slightly behind. Your draft buries the correction under a description of the credit memo process.","task":"Write a correction message that leads with the corrected number and what changed.","tips":["First sentence: the corrected figure and the direction of the change.","Then the cause, in one sentence.","People act on the number — get it in front of them fast."],"focus":["clarity","impact"],"placeholder":"Correction to yesterday's flash: April revenue is $92K lower than reported —"},
    {"id":"lead-fin-early-13","level":"early","profession":"finance","title":"The AP status question","scenario":"A vendor called the office manager asking about an unpaid invoice, and she's forwarded it to you. You need accounts payable to confirm where invoice #7788 sits in the payment run. Your draft to AP retells the whole vendor call first.","task":"Write a message to AP that leads with the specific question.","tips":["Sentence one: where is invoice #7788 in the payment queue?","Give the vendor name and amount so they can find it in seconds.","The backstory of the call adds nothing — cut it."],"focus":["clarity","concision"]},
    {"id":"lead-fin-early-14","level":"early","profession":"finance","title":"The Friday update to the controller","scenario":"You send the controller a weekly recap. This week you finished the fixed-asset reconciliation and cleared four aged AR items, but your draft spends most of its length on meetings you sat in.","task":"Write the opening 1-2 sentences of a recap that leads with what you completed.","tips":["Lead with finished work, not attended meetings.","Two outcomes, one sentence each, then stop.","If the controller reads only line one, they should know your week."],"focus":["concision","structure"],"placeholder":"This week: fixed-asset rec done and four aged AR items cleared."},
    {"id":"lead-fin-early-15","level":"early","profession":"finance","title":"The vendor overbilling flag","scenario":"Checking a contract against invoices, you found a software vendor has billed the pre-discount rate for three months — about $1,800 in overcharges. Your message to your manager starts with how you happened to be checking.","task":"Write a 2-3 sentence message that leads with the finding and the total.","tips":["First sentence: who overbilled, how much, over what period.","Recommend the next step — request a credit memo.","How you found it is one clause, not one paragraph."],"focus":["impact","precision"],"placeholder":"CloudSoft has overbilled us ~$1,800 over three months —"},
    {"id":"lead-fin-early-16","level":"early","profession":"finance","title":"The system-access request","scenario":"You need read access to the procurement module to trace purchase orders for the close, and only IT can grant it. Your draft ticket explains your entire close checklist before asking.","task":"Write a request that puts the access you need and the deadline in the first sentence.","tips":["Lead with the ask: read access to the procurement module by Wednesday.","One sentence on why — PO tracing for month-end close.","Name your manager as approver if that speeds it up."],"focus":["clarity","concision"]},
    {"id":"lead-fin-early-17","level":"early","profession":"finance","title":"The headcount number HR needs","scenario":"An HR business partner asks how many open roles are funded in the sales budget for Q3. The answer is six. Your draft reply explains how the budget was built before giving the number.","task":"Write a reply that gives the number in the first sentence, then one line of context.","tips":["Answer first: six funded openings in Q3.","Add the one caveat that matters — two are backfills, four are new.","Offer the detail file instead of narrating it."],"focus":["concision","clarity"],"placeholder":"Six funded openings in sales for Q3 —"},
    {"id":"lead-fin-early-18","level":"early","profession":"finance","title":"The overspend early warning","scenario":"Tracking actuals mid-month, you can see the facilities budget will finish roughly $25K over because of an unplanned HVAC repair. Your draft to your manager eases in with the weather and the building's age.","task":"Write a heads-up that leads with the projected overrun.","tips":["Lead with the projection: facilities ends the month ~$25K over.","Name the driver in the same breath — the HVAC repair.","Early and plain beats complete and late."],"focus":["impact","precision"],"placeholder":"Heads-up: facilities will finish ~$25K over budget this month —"},
    {"id":"lead-fin-early-19","level":"early","profession":"finance","title":"The expense-policy verdict","scenario":"A sales rep asks whether a $210 client dinner is reimbursable. Under policy it is — it's under the limit and has a business purpose. Your draft quotes the policy document at length before answering.","task":"Write a reply that gives the verdict in the first word or two.","tips":["Lead with yes or no.","Cite the one policy line that applies, not the whole section.","Tell them what to do next — submit with the receipt."],"focus":["clarity","concision"],"placeholder":"Yes — reimbursable."},
    {"id":"lead-fin-early-20","level":"early","profession":"finance","title":"The journal-entry review ask","scenario":"Your correcting entries need your manager's review before the 3pm posting cutoff, or the close slips a day. Your draft message describes each entry in detail before mentioning the deadline.","task":"Write a message that leads with the review request and the cutoff.","tips":["Sentence one: need your review on 4 entries before 3pm.","Say what's at stake — posting cutoff, close timing.","Descriptions of the entries go in the attachment."],"focus":["clarity","impact"]},
    {"id":"lead-fin-early-21","level":"early","profession":"finance","title":"The one-line model summary","scenario":"Your manager is walking into a meeting in five minutes and asks: \"What does your pricing model say?\" The model has thirty tabs, but the answer is that a 5% price increase holds volume in every scenario except the worst case.","task":"Write the one- to two-sentence answer you'd send back immediately.","tips":["Give the conclusion, not the contents.","Name the one exception so they aren't blindsided.","Five minutes means headline only — trust it."],"focus":["concision","impact"],"placeholder":"The model says a 5% increase holds volume in all but the worst case —"},
    {"id":"lead-fin-early-22","level":"early","profession":"finance","title":"The cash question from the treasurer","scenario":"The treasury manager pings you: \"What did operating cash look like at month end?\" The number is $4.2M, down $300K from last month due to an annual insurance payment. Your draft starts with how the report is compiled.","task":"Write a reply that gives the number and the one driver in two sentences.","tips":["Number first: $4.2M at month end.","Direction and driver second: down $300K on the insurance payment.","No compilation narrative — they asked for the figure."],"focus":["precision","concision"]},
    {"id":"lead-fin-early-23","level":"early","profession":"finance","title":"The meeting request that hides its purpose","scenario":"You want 20 minutes with your manager to propose cleaning up the chart of accounts — a dozen unused cost centers are cluttering every report. Your draft says \"could we chat sometime about some report stuff.\"","task":"Write a meeting request that states the purpose and time needed up front.","tips":["Lead with the topic and the ask: 20 minutes on retiring unused cost centers.","One sentence on the payoff — cleaner reports, faster close.","Vague requests get deferred; specific ones get booked."],"focus":["clarity","precision"],"placeholder":"Could I get 20 minutes this week to propose retiring 12 unused cost centers?"},
    {"id":"lead-fin-early-24","level":"early","profession":"finance","title":"The two-option posting question","scenario":"A $9,000 invoice was coded to the wrong department. You can fix it with a reclass entry this month or net it against next month's allocation. You need your manager's pick by tomorrow, but your draft explains general ledger mechanics first.","task":"Write an email that leads with the decision and deadline, then presents the two options in one line each.","tips":["Open with: need your pick by tomorrow — reclass now or net next month.","One line per option with its tradeoff.","Recommend one if you have a view."],"focus":["structure","clarity"],"placeholder":"Need your call by tomorrow on a $9K miscoding — two options:"},
    {"id":"lead-fin-early-25","level":"early","profession":"finance","title":"The thank-you with a second ask","scenario":"The warehouse supervisor pulled inventory counts for you yesterday on short notice. Now you need one more thing — the damaged-goods log for the same period. Your draft is a paragraph of thanks with the new ask hidden at the end.","task":"Write a message that makes the new ask clear in the first two sentences while staying gracious.","tips":["Pair the thanks and the ask up front — don't bury the favor.","Be specific: the damaged-goods log for March.","Give a deadline so it doesn't drift."],"focus":["clarity","audience"]}
  ],
  "start-with-the-audience": [
    {"id":"audience-fin-early-01","level":"early","profession":"finance","title":"Accruals, explained to marketing","scenario":"The marketing manager is confused: \"Why does my budget show $30K spent on the event when we haven't paid the invoice yet?\" The real answer involves accrual accounting. She doesn't need the textbook — she needs to know what it means for her budget.","task":"Write a 2-3 sentence explanation in her terms, without the word 'accrual' doing the work alone.","tips":["Translate: we count the cost when the event happens, not when the cash leaves.","Anchor it to her question — the $30K is real spend against her budget.","Skip the debits and credits entirely."],"focus":["audience","clarity"],"placeholder":"We record the cost when the event happens, not when we pay —"},
    {"id":"audience-fin-early-02","level":"early","profession":"finance","title":"The variance report a department head can use","scenario":"You send the engineering director her monthly budget report. Your draft commentary reads: \"Unfavorable variance of $22K in OpEx driven by timing of prepaid amortization and unbudgeted contractor spend.\" She reads it as noise.","task":"Rewrite the commentary in 2-3 sentences she can act on.","tips":["Name what she controls — contractor spend — separately from timing noise.","Say which part needs a decision from her and which doesn't.","Use her words: contractors, software renewals — not amortization."],"focus":["audience","clarity"],"placeholder":"You're $22K over this month. Most of it is timing, but one part needs your attention:"},
    {"id":"audience-fin-early-03","level":"early","profession":"finance","title":"Why the invoice isn't paid yet","scenario":"A project manager forwards an angry vendor email asking why a $14K invoice is 20 days late. The truth: it was never matched to a purchase order, so it's been sitting in an exception queue. The PM doesn't know what PO matching is.","task":"Write a 2-3 sentence reply the PM can understand and partly forward to the vendor.","tips":["Lead with the practical answer: it stalled because paperwork didn't match, and here's the fix.","Give the PM one action — confirm the PO number.","Include a payment date they can pass on."],"focus":["audience","clarity"]},
    {"id":"audience-fin-early-04","level":"early","profession":"finance","title":"Capitalize vs. expense, for a builder","scenario":"An engineering lead asks why the $60K spent on the new internal tool \"disappeared\" from his department's monthly costs. The answer: it was capitalized and will show up as depreciation over three years. He thinks finance is hiding something.","task":"Write a 3-4 sentence explanation that makes the treatment feel sensible, not sneaky.","tips":["Explain the idea in his terms: big build costs get spread over the years the tool is used.","Show the arithmetic: $60K becomes about $1.7K/month for 36 months.","Reassure him nothing was removed — it moved and stretched."],"focus":["audience","clarity"],"placeholder":"Nothing disappeared — the $60K got spread over the three years we'll use the tool."},
    {"id":"audience-fin-early-05","level":"early","profession":"finance","title":"Budget vs. forecast for a new manager","scenario":"A newly promoted team lead asks why you keep sending him both a \"budget\" and a \"forecast\" and which one he should manage to. You've never had to explain the difference to someone outside finance.","task":"Write a 3-4 sentence explanation of the difference and which number he should use.","tips":["Budget = the plan set in December; forecast = the current best guess.","Tell him plainly which one to manage to and why.","One concrete example makes it stick — use his contractor line."],"focus":["audience","clarity"]},
    {"id":"audience-fin-early-06","level":"early","profession":"finance","title":"The month-end blackout, announced","scenario":"During the first three business days of each month, finance can't run ad-hoc reports because the books are closing. You're drafting the reminder to all department admins, and your first draft is full of close-calendar jargon.","task":"Write a 2-3 sentence announcement any admin can understand and act on.","tips":["Lead with what they experience: no custom reports the first 3 business days.","Say what to do instead — queue requests, we deliver day 4.","Cut every word of close mechanics."],"focus":["audience","concision"],"placeholder":"Finance can't run custom reports the first 3 business days of the month —"},
    {"id":"audience-fin-early-07","level":"early","profession":"finance","title":"The audit ask, translated","scenario":"You need the customer success lead to pull five signed contracts for the auditors by Friday. Your draft says \"the auditors require executed agreements supporting revenue recognition for sampled transactions.\" She won't know what that means or why it's urgent.","task":"Rewrite the request in 2-3 sentences in her language, with the deadline clear.","tips":["Say it plainly: auditors picked 5 deals to check; we need the signed contracts.","Explain the stake in one clause — the audit can't finish without them.","List the five customer names so she can start immediately."],"focus":["audience","clarity"]},
    {"id":"audience-fin-early-08","level":"early","profession":"finance","title":"Depreciation for the ops team","scenario":"The warehouse manager sees a $4,100 monthly charge called \"depreciation — equipment\" on his cost report and wants it removed because \"we didn't buy anything this month.\" You need to explain without a lecture.","task":"Write a 2-3 sentence explanation of what the charge is and why it recurs.","tips":["Anchor to the real object: the forklifts bought last year, paid for month by month on the report.","Confirm what he suspects is half-right — no new cash left this month.","Say when the charge will end."],"focus":["audience","clarity"],"placeholder":"That's the cost of the forklifts from last year, spread over their useful life —"},
    {"id":"audience-fin-early-09","level":"early","profession":"finance","title":"One report, two readers","scenario":"Your manager asks you to send the quarterly spend summary to both the CFO's chief of staff and the office managers who submit the data. Your draft is written for finance eyes — dense tables, account codes, no takeaway.","task":"Write the 2-3 sentence cover note, choosing the office managers as the primary audience.","tips":["Pick one primary reader and write for them; the other can skim.","Lead with what the office managers should check or fix.","Put the account-code detail in the attachment, not the note."],"focus":["audience","structure"]},
    {"id":"audience-fin-early-10","level":"early","profession":"finance","title":"The chargeback complaint","scenario":"A sales manager is upset about a $6K \"IT allocation\" on her team's report: \"I never approved this.\" The charge is her team's share of company-wide software licenses, split by headcount. Your first instinct is to paste the allocation methodology.","task":"Write a 2-3 sentence reply that explains the charge in her terms and tells her what's controllable.","tips":["Say what it pays for: her team's share of the licenses everyone uses.","Explain the split simply — by headcount, so it moves with team size.","Be honest about control: she can question the license list, not the split."],"focus":["audience","clarity"]},
    {"id":"audience-fin-early-11","level":"early","profession":"finance","title":"Explaining a reforecast to the team owner","scenario":"Because revenue is tracking below plan, every department must cut discretionary spend 10% for the rest of the year. You're drafting the note to the customer success lead, and it currently opens with company-level revenue commentary she can't act on.","task":"Write a 3-4 sentence note that leads with what changes for her team.","tips":["Lead with her number: her discretionary budget drops $18K for H2.","Name what counts as discretionary in her budget — travel, events, tools.","One sentence of company context is enough; her actions matter more."],"focus":["audience","impact"],"placeholder":"Your team's discretionary budget for H2 comes down $18K —"},
    {"id":"audience-fin-early-12","level":"early","profession":"finance","title":"The new analyst's first close","scenario":"A new analyst joins your team the week before close, and you're writing her a note about what to expect. Your draft references \"the usual flux file,\" \"PBC list,\" and \"the recharge process\" — shorthand she can't possibly know yet.","task":"Rewrite a 3-4 sentence orientation note that assumes zero context.","tips":["Spell out every piece of shorthand or drop it.","Tell her the shape of the week: what happens day 1-5 and where she fits.","Name one person to ask when stuck."],"focus":["audience","clarity"]},
    {"id":"audience-fin-early-13","level":"early","profession":"finance","title":"The PO process, sold not recited","scenario":"A designer bought $900 of stock photos on a personal card because \"the PO process takes forever.\" You need to explain why purchases need POs — without reading policy at someone who's already annoyed.","task":"Write a 2-3 sentence explanation that connects the process to something she cares about.","tips":["Lead with her stake: with a PO, she's never out of pocket and pays faster.","One sentence on why the company needs it — spend visibility, vendor terms.","Offer the shortcut: you'll walk her through the first one."],"focus":["audience","impact"]},
    {"id":"audience-fin-early-14","level":"early","profession":"finance","title":"Numbers for the all-hands slide","scenario":"The internal comms lead asks for \"a line about Q1 finances\" for the company all-hands. You draft: \"Q1 revenue of $8.4M represents 12% YoY growth with gross margin expansion of 180bps.\" Half the company won't parse 'bps'.","task":"Rewrite the line so any employee understands it in one read.","tips":["Keep the two numbers that matter; translate the rest.","'Margin expansion of 180bps' becomes plain words about keeping more of each dollar.","Say why it matters to the room in a few words."],"focus":["audience","clarity"],"placeholder":"We brought in $8.4M in Q1 — 12% more than last year — and kept more of each dollar than before."},
    {"id":"audience-fin-early-15","level":"early","profession":"finance","title":"The credit memo, explained to sales","scenario":"An account executive asks why his customer's invoice shows a $2,300 credit he doesn't recognize. It reverses a billing error from January. He's about to get on a call with the customer and needs to sound sure-footed.","task":"Write a 2-3 sentence explanation he can relay on the call.","tips":["Give him the customer-safe sentence first.","One line of internal context so he understands it himself.","Confirm the net amount the customer actually owes."],"focus":["audience","clarity"]},
    {"id":"audience-fin-early-16","level":"early","profession":"finance","title":"Why finance asks twice","scenario":"A team lead grumbles that he already gave you his contractor hours \"last week for the other report.\" That was the forecast; this is the accrual for actuals. To him it's the same numbers twice. You want to fix the frustration, not just this request.","task":"Write a 2-3 sentence reply that explains the difference in his terms and makes this ask easy.","tips":["Name the difference plainly: one was your estimate, this is what actually happened.","Acknowledge the annoyance without groveling.","Offer to merge the two asks into one going forward."],"focus":["audience","clarity"]},
    {"id":"audience-fin-early-17","level":"early","profession":"finance","title":"Calibrating altitude for the CFO's staffer","scenario":"The CFO's chief of staff asks for \"a quick read on travel spend this year.\" You have a 40-line breakdown by department and trip type. She needs two sentences for a leadership brief, not your workpaper.","task":"Write the 2-sentence answer at the altitude she needs.","tips":["Total, trend, and the one thing leadership should know.","No department-by-department tour.","Offer the breakdown as an attachment if wanted."],"focus":["audience","concision"],"placeholder":"Travel is $310K YTD, running 8% under budget —"},
    {"id":"audience-fin-early-18","level":"early","profession":"finance","title":"The expense rejection, without the code","scenario":"You have to tell a new employee his expense report was rejected because he used the wrong cost center and missed an itemized receipt. Your draft quotes the system's rejection codes verbatim. He's three weeks into the job.","task":"Write a 2-3 sentence note that tells him exactly how to fix and resubmit.","tips":["Translate the codes into two plain fixes.","Point him to where the right cost center lives.","Warm tone — three weeks in, this is a teaching moment."],"focus":["audience","clarity"]},
    {"id":"audience-fin-early-19","level":"early","profession":"finance","title":"Cash vs. profit for a founder-type","scenario":"A product director asks: \"We're profitable — why is there a spending freeze?\" The answer: customers are paying slowly, so cash is tight even though the P&L looks fine. You get one short reply to make this land.","task":"Write a 2-3 sentence explanation of profit vs. cash using this situation.","tips":["Use the concrete driver: sales are booked, cash arrives 60+ days later.","One image helps: profit is the scoreboard, cash is what's in the register.","Keep it blameless — no department caused this."],"focus":["audience","clarity"],"placeholder":"We've earned the revenue on paper, but the cash hasn't arrived yet —"},
    {"id":"audience-fin-early-20","level":"early","profession":"finance","title":"The survey you actually need filled in","scenario":"You need every budget owner to confirm their open purchase orders by Thursday so you can release unused funds. Your draft email is titled \"PO Accrual Validation — Action Required\" and opens with process language. Most will ignore it.","task":"Rewrite the subject line and opening 2 sentences so a busy budget owner acts.","tips":["Subject: what they get or lose — 'Confirm your open POs by Thu or funds stay locked.'","First sentence: the action and the 5 minutes it takes.","Their incentive up front: confirmed = money freed for their own use."],"focus":["audience","impact"]},
    {"id":"audience-fin-early-21","level":"early","profession":"finance","title":"Explaining the annual true-up","scenario":"Department heads just got hit with a year-end insurance true-up allocation, and the HR director wants to know why her costs jumped $9K in one month \"with no warning.\" The real story: the insurer's final bill exceeded the monthly estimates.","task":"Write a 3-4 sentence explanation that owns the surprise and prevents the next one.","tips":["Lead with the cause in her terms: the year's estimates ran low; the final bill settles the gap.","Acknowledge the timing pain honestly.","Commit to a fix — quarterly estimate reviews so the jump shrinks."],"focus":["audience","clarity"]},
    {"id":"audience-fin-early-22","level":"early","profession":"finance","title":"The board-pack number, sanity-checked","scenario":"Your manager asks you to draft a one-line explanation of why headcount costs rose 15% for the board pack. Your instinct is analyst-speak: \"increase driven by annualization of prior-year hires and merit cycle.\" Board readers want cause and expectation.","task":"Write the one- to two-sentence version for a board reader.","tips":["Plain cause: people hired last year are now on payroll all year, plus raises.","Say whether it was planned — that's the board's real question.","No 'annualization' — say what it means instead."],"focus":["audience","precision"],"placeholder":"Headcount costs rose 15%, as planned: last year's hires are now on payroll for a full year —"},
    {"id":"audience-fin-early-23","level":"early","profession":"finance","title":"The procurement handoff","scenario":"You've finished analyzing three shipping vendors and procurement will run the negotiation. Your handoff draft is a tour of your spreadsheet. Procurement needs the leverage points: current rates, volumes, and where the savings are.","task":"Write a 3-4 sentence handoff note framed around what procurement can use.","tips":["Lead with the negotiating headline: vendor B is 12% cheaper at our volumes.","Give them ammunition, not methodology.","Flag the one landmine — vendor A has a termination fee."],"focus":["audience","structure"]},
    {"id":"audience-fin-early-24","level":"early","profession":"finance","title":"Same news, two channels","scenario":"The Q2 department budgets are locked and can't be increased without VP approval. You need to tell the 14 budget owners (email) and also drop a one-liner in the managers' Slack channel. Your drafts are identical. The channels deserve different lengths.","task":"Write both: a 3-sentence email opening and a one-line Slack version.","tips":["Email: the rule, the reason, the exception path.","Slack: just the rule and where to read more.","Same fact, different depth — that's audience calibration."],"focus":["audience","concision"]},
    {"id":"audience-fin-early-25","level":"early","profession":"finance","title":"The intern's question","scenario":"A summer intern shadowing you asks what you actually do during close week. You start mentally composing something about journal entries, reconciliations, and flux analysis. She's a marketing major; this is her second week.","task":"Explain your close-week job in 2-3 sentences a smart outsider would understand.","tips":["Analogy helps: checking the month's books the way you'd balance a shared apartment ledger.","Name the output: numbers leadership can trust by day five.","If she could repeat it to a friend accurately, you've succeeded."],"focus":["audience","clarity"],"placeholder":"My job in close week is making sure last month's numbers are actually true —"}
  ],
  "structure-that-carries": [
    {"id":"structure-fin-early-01","level":"early","profession":"finance","title":"One governing idea for the variance memo","scenario":"Your monthly variance commentary for the operations department lists eleven line items in ledger order. Reading it back, there's no takeaway — just a tour. The real story: the department is on budget overall, with one genuine problem (contractor overspend) masked by two timing offsets.","task":"Write the one-sentence governing idea that should sit at the top of the memo.","tips":["One sentence that carries the whole message: on budget overall, one real issue.","Everything below should support that sentence or be cut.","If the reader stops after line one, they still leave informed."],"focus":["structure","clarity"],"placeholder":"Operations is on budget overall; the one item needing action is contractor spend, $18K over."},
    {"id":"structure-fin-early-02","level":"early","profession":"finance","title":"Three buckets for a messy close list","scenario":"Your close checklist has 14 open items scattered across a Slack thread: two missing bank statements, four unapproved journal entries, three departments late on accruals, and five small reconciling items. Your manager asked for a status structure, not a list.","task":"Group the 14 items into no more than three labeled buckets and write the one-line status for each.","tips":["Group by what unblocks them: waiting on external, waiting on approval, ours to clear.","Label each bucket with its owner and count.","Three buckets a reader can hold; fourteen items they can't."],"focus":["structure","clarity"]},
    {"id":"structure-fin-early-03","level":"early","profession":"finance","title":"SCQA for the reconciliation automation","scenario":"You want to pitch your manager on automating the credit-card reconciliation you do by hand for six hours every month. You have the idea, the tool, and the payback — but your draft opens with tool features.","task":"Write the pitch as four sentences: Situation, Complication, Question, Answer.","tips":["Situation: the rec happens monthly and matters. Complication: six manual hours and two recent errors.","The question should be the one your manager is now asking themselves.","Answer: the specific proposal with cost and time saved."],"focus":["structure","impact"],"placeholder":"Every month I reconcile 400 card transactions by hand. It takes six hours and produced two errors this quarter."},
    {"id":"structure-fin-early-04","level":"early","profession":"finance","title":"PREP for the travel question","scenario":"In the budget review, the operations director will ask why travel is 30% over. You know the answer: two unplanned client-site visits, both approved by her own deputy. You'll be answering out loud with no slides.","task":"Script a 4-sentence spoken answer using PREP: Point, Reason, Example, Point.","tips":["Point first: the overage is two approved, unplanned client visits.","Example: name one trip with its cost.","Restate the point with the forward look — the rest of the line is on plan."],"focus":["structure","clarity"]},
    {"id":"structure-fin-early-05","level":"early","profession":"finance","title":"The audit findings, grouped","scenario":"The auditors sent seven observations from interim fieldwork: three about missing approval signatures, two about stale user access in the ERP, one late reconciliation, and one policy document out of date. You're summarizing them for the controller.","task":"Write a summary that groups the seven findings into themes with a one-line status each.","tips":["Group by root cause, not by the order the auditors listed them.","Approvals, access, housekeeping — three themes cover all seven.","Say which theme carries real risk and which is paperwork."],"focus":["structure","precision"]},
    {"id":"structure-fin-early-06","level":"early","profession":"finance","title":"The forecast email skeleton","scenario":"You're drafting the quarterly forecast email to department heads. Your current draft interleaves instructions, deadlines, template links, and context in the order you thought of them. Nobody will extract the three things they must do.","task":"Rewrite the email as a governing sentence plus exactly three numbered actions.","tips":["Top line: what this is and when it's due.","Three actions max, each starting with a verb and a date.","Context goes below the actions or into a link — never between them."],"focus":["structure","concision"],"placeholder":"Q3 forecast inputs are due Friday June 20. Three things: 1)"},
    {"id":"structure-fin-early-07","level":"early","profession":"finance","title":"Ordering the discrepancy story","scenario":"You found that petty cash is $240 short, and your writeup tells events in the order you discovered them: the count, the log review, the missing voucher, the conclusion. Your manager needs conclusion-first with the evidence beneath.","task":"Reorder the writeup: verdict in sentence one, then the two strongest pieces of support.","tips":["Detective-story order buries the lede — invert it.","Verdict, then evidence ranked by strength, not chronology.","Close with the recommended control fix."],"focus":["structure","clarity"]},
    {"id":"structure-fin-early-08","level":"early","profession":"finance","title":"The budget deck outline","scenario":"Your manager asked you to outline a 5-slide deck for the department budget review. Your first cut has nine slides: one per expense category. The categories aren't the story — the story is 'on plan except two decisions needed.'","task":"Write the 5 slide titles as full-sentence assertions that carry the argument.","tips":["Each title states a finding, not a topic: 'Contractor spend needs a decision' beats 'Contractors'.","Slide 1 carries the governing message; slides 2-4 support it; slide 5 is the ask.","If someone reads only titles, they get the whole argument."],"focus":["structure","impact"]},
    {"id":"structure-fin-early-09","level":"early","profession":"finance","title":"Twelve questions, three buckets","scenario":"You have twelve open questions for the sales operations team before you can finish the commissions accrual. Sending twelve bullets guarantees you get answers to four. The questions cluster naturally: data you need, policy calls, and confirmations.","task":"Write the email that groups the twelve into three labeled sections with a deadline per section.","tips":["Name each bucket by the kind of answer needed — pull this data, decide this, confirm this.","Put the fastest bucket first so momentum starts.","One deadline per bucket beats one vague deadline for all."],"focus":["structure","clarity"]},
    {"id":"structure-fin-early-10","level":"early","profession":"finance","title":"The month in one pyramid","scenario":"Your manager wants a monthly summary she can lift into her own report to the controller. You have the trial balance, the flux file, and a dozen observations. She needs one message with at most three supporting points.","task":"Write the summary: one governing sentence, then up to three supporting sentences.","tips":["Pick the single message the month actually supports — don't average your observations.","Each support point should be a different kind of evidence, not three restatements.","Anything that doesn't hold up the top line gets cut, even if interesting."],"focus":["structure","concision"],"placeholder":"The month closed clean and on schedule, with three things worth knowing:"},
    {"id":"structure-fin-early-11","level":"early","profession":"finance","title":"SCQA for the software renewal","scenario":"The team's planning tool renews in 45 days at a 20% price increase. You've checked usage: only 9 of 25 licenses were active last quarter. You want the controller to approve cutting to 12 licenses, but your draft starts with the license report.","task":"Write the recommendation in SCQA order, four sentences.","tips":["Situation: renewal coming. Complication: paying for 25, using 9, price rising 20%.","Question: how many licenses should we renew?","Answer: 12 licenses, saving $X — with the number computed, not implied."],"focus":["structure","impact"]},
    {"id":"structure-fin-early-12","level":"early","profession":"finance","title":"The handover doc that carries itself","scenario":"You're going on vacation during the next close, and your handover doc is a stream of consciousness: passwords mixed with process steps mixed with warnings. Your covering analyst will read it at 8pm on day 1, mid-panic.","task":"Write the top section: a one-line purpose and the three headings you'd organize everything under.","tips":["Structure for the panicked reader: 'Do these in order', 'If something breaks', 'Where things live'.","Order by when they'll need it, not by when you thought of it.","The doc's first line should say what it covers and what it doesn't."],"focus":["structure","audience"]},
    {"id":"structure-fin-early-13","level":"early","profession":"finance","title":"The AR aging, told as one idea","scenario":"The AR aging report shows 34 overdue invoices. Your draft commentary walks the report top to bottom. The actual signal: 80% of the overdue value sits with three customers, and one of them has gone quiet for 60 days.","task":"Write a 3-sentence commentary structured around that one governing idea.","tips":["Lead with the concentration: three customers are the whole story.","The quiet customer is your complication — give it its own sentence.","The other 31 invoices earn one clause, not a paragraph."],"focus":["structure","precision"],"placeholder":"Three customers hold 80% of our overdue receivables —"},
    {"id":"structure-fin-early-14","level":"early","profession":"finance","title":"PREP under a deadline question","scenario":"The controller stops by your desk: \"Will the fixed-asset register be ready for the auditors Monday?\" The honest answer is yes, if IT restores the tagging report by Thursday. You have ten seconds to answer in a way that doesn't wobble.","task":"Script the spoken answer in PREP form, 3-4 sentences.","tips":["Point: yes, with one dependency.","Reason and example: the tagging report, expected Thursday, and your fallback if it slips.","End on the point again — Monday stands."],"focus":["structure","clarity"]},
    {"id":"structure-fin-early-15","level":"early","profession":"finance","title":"Grouping the expense-policy violations","scenario":"Your quarterly expense audit found 19 policy violations. Listed one-by-one they read as a rap sheet. Grouped, they say something useful: 13 are missing itemized receipts (a training gap), 4 are late submissions, and 2 are genuine limit breaches needing follow-up.","task":"Write a 3-4 sentence summary organized by those groups, ordered by what deserves attention.","tips":["Order by severity, not frequency — the 2 breaches lead.","Attach a different action to each group: escalate, remind, train.","The grouping IS the insight; make it visible in the structure."],"focus":["structure","impact"]},
    {"id":"structure-fin-early-16","level":"early","profession":"finance","title":"The two-minute model walkthrough","scenario":"Your manager gives you two minutes at the team meeting to walk through your new departmental cost model. Your instinct is to share your screen and go tab by tab. Two minutes of tabs convinces no one.","task":"Outline the walkthrough as: the answer, the three assumptions that drive it, the one risk.","tips":["Open with what the model concludes, not what it contains.","Pick the three assumptions the answer is most sensitive to.","Name the risk yourself before someone else does."],"focus":["structure","impact"],"placeholder":"The model says the department can absorb the new hires within budget. Three assumptions drive that:"},
    {"id":"structure-fin-early-17","level":"early","profession":"finance","title":"The status email with three audiences' needs","scenario":"Your weekly close-status email goes to the controller (wants: on schedule or not), the accounting team (wants: who owes what), and IT (wants: any system issues). Your current draft mixes all three conversations in one paragraph.","task":"Restructure it: one governing status line, then three labeled sections, one per audience need.","tips":["The top line serves everyone: overall status and date.","Section headers let each reader jump to their part.","Never make IT read journal-entry assignments to find their bit."],"focus":["structure","audience"]},
    {"id":"structure-fin-early-18","level":"early","profession":"finance","title":"From data dump to argument","scenario":"You pulled quarterly software spend by team: eight teams, three quarters, a 24-cell table. Pasted raw into the email, it says nothing. Studied, it shows spend flat everywhere except one team, where it doubled after an unapproved tool purchase.","task":"Write the 2-3 sentence message where the structure delivers the insight and the table becomes backup.","tips":["Lead with the pattern: flat everywhere but one place.","Name the exception and its cause in sentence two.","The table goes below a line that tells readers what to see in it."],"focus":["structure","precision"],"placeholder":"Software spend is flat across seven of eight teams —"},
    {"id":"structure-fin-early-19","level":"early","profession":"finance","title":"The escalation with a spine","scenario":"A department has ignored three requests for their inventory count sheets, and the close now slips tomorrow without them. You're escalating to your manager. Your draft is a chronological grievance log — dates, sends, silences.","task":"Restructure into: the ask of your manager, the impact, then the one-line history.","tips":["Your manager needs the ask first: please call their director today.","Impact second: close slips tomorrow without the sheets.","The three ignored emails become one sentence of evidence, not the plot."],"focus":["structure","impact"]},
    {"id":"structure-fin-early-20","level":"early","profession":"finance","title":"One idea per paragraph","scenario":"Your quarter-end accruals memo has a paragraph that covers the accrual total, a policy change, a system issue, and a thank-you — four ideas in six sentences. Readers retain none of it.","task":"Split it: write the four one-sentence paragraph openers, in the order a reader needs them.","tips":["One idea per paragraph, opener states the idea.","Order by reader priority: number, change, issue, thanks.","If two openers overlap, you have three ideas, not four."],"focus":["structure","clarity"]},
    {"id":"structure-fin-early-21","level":"early","profession":"finance","title":"The capex request, structured for a yes","scenario":"The warehouse team wants finance to support their $45K forklift replacement request before it goes to the VP. The case is sound: repairs on the old unit are running $800/month and rising, plus two safety incidents. Your draft buries the economics under the incident reports.","task":"Structure a 4-sentence support note: recommendation, economic case, risk case, ask.","tips":["Recommendation up top: replace now rather than repair.","Economics in one sentence with the crossover math.","Safety is the clincher, not the opener — sequence deliberately."],"focus":["structure","impact"],"placeholder":"Finance supports replacing the forklift now: repair costs cross the purchase price within 14 months."},
    {"id":"structure-fin-early-22","level":"early","profession":"finance","title":"Answering three questions in one email","scenario":"The marketing director's email asks three things: why April looks high, whether May budget can move to June, and who approves conference spend. Your draft answers them woven together in two dense paragraphs. She'll have to excavate.","task":"Rewrite as three labeled answers, one line each, in her order.","tips":["Mirror her structure — answer in the order asked.","Label each answer with a shorthand of her question.","One line per answer; detail only where the answer needs defending."],"focus":["structure","concision"]},
    {"id":"structure-fin-early-23","level":"early","profession":"finance","title":"The prepaids explanation ladder","scenario":"The new office manager asks why the $24K annual insurance premium she paid in January doesn't show as a January cost. The answer has three levels: what she sees, why it's spread, what to expect monthly. Your draft gives all three at once in a knot.","task":"Write a 3-sentence explanation where each sentence takes exactly one step down the ladder.","tips":["Sentence 1: what she observes is correct and intended.","Sentence 2: the reason — the coverage is used over 12 months, so the cost is too.","Sentence 3: what she'll see going forward — $2K per month through December."],"focus":["structure","audience"]},
    {"id":"structure-fin-early-24","level":"early","profession":"finance","title":"The project post-mortem summary","scenario":"The ERP data-migration project you supported finished two weeks late but under budget. You're writing the finance section of the post-mortem. Your notes are a jumble of things that went right and wrong in no order.","task":"Write a 4-sentence section: verdict, what drove the budget result, what drove the delay, one change for next time.","tips":["Verdict sentence holds both facts: late but under budget.","Give the delay and the savings separate sentences — don't blend causes.","End with one specific recommendation, not a list of lessons."],"focus":["structure","clarity"]},
    {"id":"structure-fin-early-25","level":"early","profession":"finance","title":"Rebuilding the FAQ answer","scenario":"You keep answering the same question from budget owners: \"Can I move money between my budget lines?\" Your usual reply is a long paragraph mixing the rule, the exceptions, and the process. You're finally writing the canonical answer for the finance wiki.","task":"Write the answer as: one-line rule, the two exceptions, the process in one line.","tips":["Rule first, stated absolutely — then exceptions carve it back.","Two exceptions max; if you have five, the rule is wrong.","End with exactly where to click or who to email."],"focus":["structure","clarity"],"placeholder":"Yes — you can move budget between lines within your own department, with two exceptions:"}
  ],
  "cut-to-the-bone": [
    {"id":"concise-fin-early-01","level":"early","profession":"finance","title":"The 'just reaching out' opener","scenario":"Your draft to a department admin begins: \"Hi! I just wanted to quickly reach out and touch base regarding the outstanding invoices that we discussed previously, whenever you get a chance.\" Twenty-six words, zero content.","task":"Rewrite the opener in under ten words that carry the actual request.","tips":["Cut 'just', 'quickly', 'reach out', 'touch base' — all filler.","'Whenever you get a chance' surrenders your deadline; name one instead.","The first sentence should survive being the only sentence."],"focus":["concision","clarity"],"placeholder":"Following up on the three outstanding invoices —"},
    {"id":"concise-fin-early-02","level":"early","profession":"finance","title":"Nominalizations in the close memo","scenario":"Your close memo says: \"We will perform a reconciliation of the bank accounts and conduct a review of outstanding items, followed by the preparation of adjusting entries.\" Every action is buried in a noun.","task":"Rewrite the sentence using verbs, cutting at least a third of the words.","tips":["'Perform a reconciliation' → 'reconcile'; 'conduct a review' → 'review'.","Nouns hide actors; verbs commit them.","Read it aloud — if it sounds like a policy manual, keep cutting."],"focus":["concision","clarity"],"placeholder":"We'll reconcile the bank accounts, review outstanding items, and"},
    {"id":"concise-fin-early-03","level":"early","profession":"finance","title":"Halve the variance paragraph","scenario":"Your variance note runs 90 words: \"It should be noted that the increase in utilities expense is primarily attributable to the fact that rates were increased by the provider effective January, and additionally, usage was higher than anticipated due to the colder-than-normal winter weather conditions experienced during the period...\" and so on.","task":"Rewrite the note in 45 words or fewer without losing a fact.","tips":["'It should be noted that' notes nothing — delete.","'Due to the fact that' → 'because'.","Two causes, two clauses: rates rose, usage rose. Done."],"focus":["concision","precision"]},
    {"id":"concise-fin-early-04","level":"early","profession":"finance","title":"The hedge stack","scenario":"Your discrepancy flag reads: \"I could be wrong, but I think there might possibly be a small issue with the March depreciation figure, which seems like it may be somewhat overstated, at least as far as I can tell.\" Six hedges guard one finding.","task":"Rewrite in one sentence with at most one calibrated qualifier.","tips":["Keep the one honest uncertainty; delete the reflexive ones.","'I think X is overstated — checking now' is confident and honest.","Stacked hedges make a correct finding sound like a guess."],"focus":["concision","impact"],"placeholder":"March depreciation looks overstated by roughly $2K —"},
    {"id":"concise-fin-early-05","level":"early","profession":"finance","title":"Meta-commentary in the report note","scenario":"Your report cover note spends its first three sentences describing itself: \"This email contains the monthly spend report. In the report you will find spending by category. The purpose of this report is to keep you informed of your spending.\" The reader still knows nothing.","task":"Replace the three sentences with one that says something about the numbers.","tips":["Don't describe the report — deliver its headline.","'You'll find X inside' wastes the reader's best attention.","One finding beats three sentences of table-of-contents."],"focus":["concision","impact"],"placeholder":"Your team's spend is on budget through May, with one line to watch:"},
    {"id":"concise-fin-early-06","level":"early","profession":"finance","title":"Redundant pairs in the policy note","scenario":"Your draft of the expense-policy reminder says employees must submit \"each and every receipt\" with \"full and complete documentation\" in a \"timely and prompt manner\" for \"review and approval.\" It reads like a lease agreement.","task":"Rewrite the sentence keeping one word from each pair.","tips":["Legal doublets add no meaning outside contracts.","'Every receipt, fully documented, within 5 days' — done.","Plain rules get followed more than ornate ones."],"focus":["concision","clarity"]},
    {"id":"concise-fin-early-07","level":"early","profession":"finance","title":"The 60-word Slack that should be 15","scenario":"You're asking a colleague to re-run one report: \"Hey! Hope your week is going well. So I was looking at the output from yesterday and I noticed the date range seems off, so when you have a moment, could you possibly re-run it? No rush at all!\" The close deadline says otherwise.","task":"Rewrite in 20 words or fewer, keeping it friendly and naming the real deadline.","tips":["One greeting word is plenty.","'No rush' is a lie during close — say when you need it.","Friendly and brief are compatible."],"focus":["concision","clarity"],"placeholder":"Hey — yesterday's report used the wrong date range. Could you re-run with March 1-31 by 2pm?"},
    {"id":"concise-fin-early-08","level":"early","profession":"finance","title":"Trimming the audit response","scenario":"Your reply to an auditor's question about a journal entry runs 140 words, restating their question, apologizing for the delay, explaining your role, and finally answering in the last sentence. Auditors bill by the hour.","task":"Rewrite the reply in 40 words or fewer, answer first.","tips":["Never restate the question back — they wrote it.","Cut the role explanation; your signature says who you are.","Answer, evidence attached, offer to discuss. Three moves, done."],"focus":["concision","structure"]},
    {"id":"concise-fin-early-09","level":"early","profession":"finance","title":"The throat-clearing forecast intro","scenario":"Your forecast email begins: \"As you may already be aware, it is that time of the quarter again when we go through our regular forecasting process, which as always is an important part of how we plan.\" Thirty-eight words before any information.","task":"Delete the throat-clearing and write the real first sentence.","tips":["'As you may already be aware' — then why say it?","Start where the information starts: what's due, when.","Ceremony costs attention you need for the deadline."],"focus":["concision","impact"],"placeholder":"Q3 forecast templates are due back Friday June 20."},
    {"id":"concise-fin-early-10","level":"early","profession":"finance","title":"One footnote, half the words","scenario":"A footnote in your spend report reads: \"Note that the figures presented in the table above do not include amounts related to contractor spending, which are excluded due to the fact that they are reported separately in a different report which is distributed on a monthly basis.\" 46 words.","task":"Rewrite the footnote in 15 words or fewer.","tips":["'Note that' and 'presented above' locate nothing — cut.","One fact: contractors are reported separately (monthly).","Footnotes earn their place by being glanceable."],"focus":["concision","precision"],"placeholder":"Excludes contractor spend, reported separately each month."},
    {"id":"concise-fin-early-11","level":"early","profession":"finance","title":"The double-apology deadline reminder","scenario":"Your reminder to a late department reads: \"Sorry to chase, and apologies if this crossed with your reply, but I wanted to gently flag that the accrual template is still outstanding, sorry for the noise if you've already sent it!\" Three apologies, no deadline.","task":"Rewrite in two sentences: zero apologies, one deadline.","tips":["A reminder for something owed needs no apology.","State the fact and the new deadline; stop.","'Gently flag' softens you, not the message."],"focus":["concision","impact"]},
    {"id":"concise-fin-early-12","level":"early","profession":"finance","title":"Cutting the process tour","scenario":"Asked how you calculated the commission accrual, you drafted five sentences describing your process: opened the CRM export, filtered closed deals, applied the rate table, cross-checked exceptions, summed the result. The answer they need is the method in one line, not the diary.","task":"Compress the five sentences into one that states the method.","tips":["Method, not journey: 'closed deals × rate table, exceptions checked by hand.'","Keep the one detail that builds trust — the exception check.","Offer the workpaper for anyone who wants the diary."],"focus":["concision","clarity"],"placeholder":"Closed March deals from the CRM, times the rate table, with the 6 exceptions checked manually."},
    {"id":"concise-fin-early-13","level":"early","profession":"finance","title":"The subject line that's a paragraph","scenario":"Your email subject reads: \"Question regarding the treatment of the marketing invoices we discussed last week in relation to the April close timing.\" Inboxes truncate at about 60 characters; yours dies mid-thought.","task":"Write a subject line of eight words or fewer that survives truncation.","tips":["Front-load the noun and the need: 'April close: marketing invoice question'.","The details live in the body — the subject just routes it.","If it needs action, say so in word one or two."],"focus":["concision","clarity"]},
    {"id":"concise-fin-early-14","level":"early","profession":"finance","title":"De-jargoning without inflating","scenario":"Translating for a non-finance reader, you've swung the other way: \"The money that we set aside earlier in the year to cover costs that we knew were coming but hadn't been billed for yet turned out to be more than what the actual bills came to.\" 40 words for 'we over-accrued.'","task":"Rewrite in 15 words or fewer, still jargon-free.","tips":["Plain doesn't mean padded.","'We set aside more than the bills came to — the difference comes back.'","Test: shorter AND clearer than both versions."],"focus":["concision","audience"]},
    {"id":"concise-fin-early-15","level":"early","profession":"finance","title":"The status update in passive drag","scenario":"Your update reads: \"It was determined that the discrepancy had been caused by an entry that was posted twice, and a correction has been prepared and will be reviewed before it is posted.\" Nobody in the sentence did anything.","task":"Rewrite in active voice, naming who does what, in 20 words or fewer.","tips":["'I found', 'I've prepared', 'Sarah reviews' — actors and verbs.","Passive voice hides ownership exactly where ownership reassures.","Each verb you activate shortens the sentence."],"focus":["concision","clarity"],"placeholder":"I found the cause — a duplicate posting. I've drafted the fix; Sarah reviews it today."},
    {"id":"concise-fin-early-16","level":"early","profession":"finance","title":"Cutting the caveat parade","scenario":"Your forecast note carries five caveats: data as of Tuesday, one department estimated, FX held constant, new hires assumed on time, and rounding. Only two could change the answer. The parade makes the whole forecast look shaky.","task":"Rewrite the caveats: keep the two that matter, cut or demote the rest.","tips":["A caveat earns its place only if it could change the reader's decision.","Merge housekeeping caveats into one clause or a footnote.","Five caveats read as 'don't trust this'; two read as 'I know where the risk is.'"],"focus":["concision","precision"]},
    {"id":"concise-fin-early-17","level":"early","profession":"finance","title":"The meeting invite that buries the prep","scenario":"Your budget-review invite contains 130 words of scheduling history and one buried sentence that matters: attendees must bring their top three variance explanations. Half the room will arrive unprepared.","task":"Rewrite the invite body in three sentences with the prep requirement first.","tips":["Lead with what they must bring — that's the only action.","Time and room are in the calendar fields; don't repeat them in prose.","Scheduling history helps no one; delete it all."],"focus":["concision","impact"]},
    {"id":"concise-fin-early-18","level":"early","profession":"finance","title":"'In order to' and friends","scenario":"Your process doc draft: \"In order to ensure accuracy, it is necessary to first of all download the file, and subsequently at that point in time you can proceed to begin the matching process.\" The instructions are drowning.","task":"Rewrite as numbered steps, cutting every empty connector.","tips":["'In order to' → 'to'; 'at that point in time' → 'then'; 'proceed to begin' → 'start'.","Steps want imperatives: download, match, review.","A process doc is judged at 11pm on close day — write for that reader."],"focus":["concision","clarity"],"placeholder":"1. Download the file. 2."},
    {"id":"concise-fin-early-19","level":"early","profession":"finance","title":"The two-line answer trapped in six","scenario":"A colleague asked which exchange rate to use for the Canadian invoices. Your draft covers the history of the rate policy, where the rate table lives, who maintains it, and — in line six — the answer: month-end rate from the table, tab two.","task":"Rewrite in two lines: the answer, then the pointer.","tips":["Answer in line one; the source in line two.","History and maintainers belong in the wiki, not the reply.","If they ask a follow-up, answer that then — don't pre-answer everything."],"focus":["concision","clarity"],"placeholder":"Use the month-end rate. It's in the rate table, tab 2 —"},
    {"id":"concise-fin-early-20","level":"early","profession":"finance","title":"Trimming your own accomplishment","scenario":"For the team's monthly wins doc you drafted 80 words about your reconciliation cleanup, padded with adjectives — 'comprehensive', 'end-to-end', 'significantly streamlined'. The facts are strong alone: 60 aged items cleared, process now takes half the time.","task":"Rewrite the win in 25 words or fewer, letting the numbers carry it.","tips":["Cut every adjective and check what's left — here, plenty.","'Cleared 60 aged items; the rec now takes 3 hours, not 6.'","Numbers brag better than adverbs."],"focus":["concision","precision"]},
    {"id":"concise-fin-early-21","level":"early","profession":"finance","title":"The wrap-up sentence that unwinds","scenario":"Your email ends: \"Anyway, that's pretty much everything for now I think, but obviously do let me know if anything is unclear or if you need anything further from my end and I'll be happy to help out however I can!\" The strong email above it dissolves.","task":"Write a one-line closing that holds the deadline instead of dissolving it.","tips":["End on the action or the date, not on vapor.","'Questions welcome — templates still due Friday.' Done.","The last line is what they remember; spend it."],"focus":["concision","impact"],"placeholder":"Happy to walk through any line — templates still due Friday."},
    {"id":"concise-fin-early-22","level":"early","profession":"finance","title":"One number per sentence","scenario":"Your flash-report sentence: \"Revenue of $2.1M was up 4% versus budget of $2.02M and 9% versus prior year of $1.93M, though down 2% sequentially from $2.14M in March.\" Four comparisons, one sentence, zero retention.","task":"Rewrite so each sentence carries one comparison, keeping only the two that matter most.","tips":["Pick the comparisons your reader decides with — budget and prior year, usually.","One number-pair per sentence is the retention limit.","The dropped comparisons can live in the table."],"focus":["concision","precision"]},
    {"id":"concise-fin-early-23","level":"early","profession":"finance","title":"The 'quick background' that isn't","scenario":"Before asking your manager to approve a $500 write-off of an unrecoverable customer balance, your draft gives 'quick background': the customer's history, the collection attempts, the emails, the phone calls. It's 150 words for a routine approval.","task":"Rewrite the whole request in three sentences.","tips":["Routine approvals need: what, why, and the ask.","'$500 balance, customer defunct, three collection attempts failed. OK to write off?'","Keep the detail file for the one time they ask."],"focus":["concision","structure"],"placeholder":"Requesting approval to write off a $500 balance —"},
    {"id":"concise-fin-early-24","level":"early","profession":"finance","title":"Halve it, then halve it again","scenario":"Your close-completion announcement runs 120 words. Your manager challenges you: get it under 60, then under 30, without losing the three facts — closed on day 4, one immaterial item carried forward, reports out Thursday.","task":"Write the 30-word version.","tips":["Each halving forces a ranking of what matters.","Three facts, three short sentences — or one sentence with two commas.","What you cut at 30 words tells you what was padding at 120."],"focus":["concision","structure"],"placeholder":"April closed on day 4. One immaterial item carries to May. Reports out Thursday."},
    {"id":"concise-fin-early-25","level":"early","profession":"finance","title":"The recurring report, re-earned","scenario":"You inherited a weekly cash-position email with six paragraphs of standing boilerplate nobody reads. This week's actual news is one line: cash is fine, but a large tax payment hits in two weeks. The boilerplate is burying the only sentence that matters.","task":"Rewrite this week's email in three sentences or fewer, boilerplate gone.","tips":["A recurring report must re-earn its length every week.","Lead with the one live item: the tax payment and its date.","Move the standing definitions to a linked reference page — once."],"focus":["concision","impact"]}
  ],
  "precision-and-evidence": [
    {"id":"precision-fin-early-01","level":"early","profession":"finance","title":"'Significantly over' means what?","scenario":"Your variance note tells the operations director that travel is \"significantly over budget\" and \"much higher than usual.\" She reads it and still doesn't know whether to worry — is that $2K or $40K?","task":"Rewrite the sentence replacing every vague intensifier with a number, a percentage, or a date.","tips":["'Significantly' → the dollar amount and the percent over.","'Higher than usual' → higher than what baseline, by how much.","A number she can act on beats an adjective she has to interpret."],"focus":["precision","clarity"],"placeholder":"Travel is $18K over budget (42%), driven by two Q2 client visits —"},
    {"id":"precision-fin-early-02","level":"early","profession":"finance","title":"The data pull that needs an insight","scenario":"Your manager asked for last quarter's vendor spend and you're about to send the raw 200-row export. The one thing that matters is invisible in the rows: three vendors account for 70% of the spend, and one of them isn't under contract.","task":"Write the 2-3 sentence cover note that states the single insight the data supports.","tips":["Lead with the pattern, not the file: concentration in three vendors.","Flag the actionable anomaly — the uncontracted vendor.","The 200 rows are the evidence; your sentence is the finding."],"focus":["precision","impact"],"placeholder":"Three vendors are 70% of last quarter's spend, and one has no contract on file —"},
    {"id":"precision-fin-early-03","level":"early","profession":"finance","title":"What, so what, now what","scenario":"You noticed that days-sales-outstanding crept from 38 to 47 days over the quarter. You could just report the number, but your manager will ask 'and?' Behind it: collections are slowing on two large accounts, tightening cash by roughly $200K.","task":"Write a 3-sentence note structured as What, So What, Now What.","tips":["What: DSO rose 38→47 days this quarter.","So what: that's ~$200K of cash tied up, concentrated in two accounts.","Now what: propose the next step — a collections call on both."],"focus":["precision","structure"]},
    {"id":"precision-fin-early-04","level":"early","profession":"finance","title":"Pass the skeptic test","scenario":"You're claiming in a memo that switching print vendors will \"save a lot\" annually. A skeptical controller will immediately ask: how much, based on what, and net of what switching costs? Your draft has none of that.","task":"Rewrite the claim so it survives three skeptical questions: how much, from what baseline, net of what.","tips":["State the annual saving as a number with the baseline it's measured against.","Show it's net of switching costs, not gross.","Name your source — the quote, the usage data — so it isn't a guess."],"focus":["precision","impact"],"placeholder":"Switching saves ~$14K/year: $52K current spend vs. a $36K quote, net of a $2K setup fee —"},
    {"id":"precision-fin-early-05","level":"early","profession":"finance","title":"'Soon' is not a date","scenario":"You tell the auditors the remaining schedules will be ready \"soon\" and the reconciliation is \"almost done.\" They can't plan their fieldwork around your feelings about the timeline. They need dates.","task":"Rewrite the update replacing every soft time-word with a specific date or count.","tips":["'Soon' → the actual date you'll deliver.","'Almost done' → how many of how many items remain.","Commit to a date you can hold, then hold it."],"focus":["precision","clarity"],"placeholder":"3 of 12 schedules remain; all delivered by Thursday June 12 —"},
    {"id":"precision-fin-early-06","level":"early","profession":"finance","title":"The rounding that hides the story","scenario":"Your summary says gross margin was \"about the same as last quarter.\" It actually slipped from 41.2% to 39.8% — 1.4 points, worth roughly $85K. 'About the same' erases a real decline your manager needs to see.","task":"Rewrite the sentence with the precise change and its dollar consequence.","tips":["State both figures and the delta in points.","Translate the points into dollars — that's the 'so what'.","Precision here isn't pedantry; it's the difference between a flag and a miss."],"focus":["precision","impact"]},
    {"id":"precision-fin-early-07","level":"early","profession":"finance","title":"Attributing the variance to a cause","scenario":"OpEx is $30K over and your draft says it's \"due to various factors.\" That phrase tells your manager nothing and invites the question you should have answered. You actually know: $22K is a one-time legal settlement, $8K is higher software renewals.","task":"Rewrite the explanation splitting the $30K into its named, quantified causes.","tips":["'Various factors' is a confession that you didn't decompose it.","Give each cause its dollar figure; they should sum to the total.","Label the one-time versus the recurring — they mean different things."],"focus":["precision","structure"],"placeholder":"The $30K over splits into $22K one-time legal settlement and $8K higher software renewals —"},
    {"id":"precision-fin-early-08","level":"early","profession":"finance","title":"The estimate with no basis","scenario":"You told the marketing manager her year-end spend will land \"around $500K.\" She's about to make a commitment based on that. But you haven't said whether that's a firm forecast or a rough guess, or what could move it.","task":"Rewrite the estimate with its basis and its main sensitivity, in 2-3 sentences.","tips":["Say what the number is built on — YTD actuals plus committed POs.","Give the range, not just the midpoint, if there's real uncertainty.","Name the one thing that would move it most."],"focus":["precision","audience"]},
    {"id":"precision-fin-early-09","level":"early","profession":"finance","title":"Quantifying the manual-process cost","scenario":"You're arguing that the manual invoice-matching process is \"really inefficient\" and \"eats up tons of time.\" Your manager has heard vague complaints before. What lands is the actual cost: 12 hours a week across two people, and a 3% error rate.","task":"Rewrite the complaint as a quantified case in 2-3 sentences.","tips":["Convert 'tons of time' into hours per week and people involved.","Add the error dimension — 3% of how many transactions.","Numbers turn a gripe into a business case."],"focus":["precision","impact"],"placeholder":"Manual matching takes 12 hours a week across two of us, with a 3% error rate —"},
    {"id":"precision-fin-early-10","level":"early","profession":"finance","title":"The comparison with no anchor","scenario":"Your flash comment says revenue is \"up nicely\" and costs are \"well controlled.\" Up from what? Controlled against what? Without anchors these are vibes. The facts: revenue up 6% vs. budget, costs 2% under budget.","task":"Rewrite both claims with their comparison anchors and figures.","tips":["Every 'up' or 'down' needs a versus: budget, prior year, or prior period.","Pick the one anchor the reader actually decides against.","'Up 6% vs. budget' is a fact; 'up nicely' is a mood."],"focus":["precision","clarity"]},
    {"id":"precision-fin-early-11","level":"early","profession":"finance","title":"The 'material' judgment, defined","scenario":"You wrote that a discrepancy is \"not material\" and moved on. Your manager, who signs off, needs to know your threshold — is it not material at $500, or did you mean it against a $2M account? The word carries a judgment you didn't show.","task":"Rewrite the sentence to state the amount, the base, and why it clears your threshold.","tips":["Give the absolute figure and what it's a percentage of.","Name the threshold you're applying, even informally.","Show the judgment; don't just assert the conclusion."],"focus":["precision","impact"],"placeholder":"The $600 difference is 0.03% of the $2M balance — below our $5K review threshold —"},
    {"id":"precision-fin-early-12","level":"early","profession":"finance","title":"Trend, not snapshot","scenario":"You reported that overtime cost $14K this month. True but flat. The signal your manager needs is direction: it was $6K in Q1, $9K last month, $14K now — a clear climb, not a one-off.","task":"Rewrite the note so the trend, not the single number, carries the message.","tips":["One month is a dot; three months is a line.","Show the trajectory with the actual figures.","End on the implication — where it lands if the trend holds."],"focus":["precision","structure"]},
    {"id":"precision-fin-early-13","level":"early","profession":"finance","title":"The source that makes it credible","scenario":"You claim in an email that the industry benchmark for this cost ratio is 8%. The controller will ask where that came from before she'll use it. Your draft states the number bare, as if you invented it.","task":"Rewrite the claim to name the source and its date so it survives scrutiny.","tips":["A benchmark without a source is a number you made up, as far as the reader knows.","Name the report and the year it's from.","If it's your own estimate, say so — honesty is precision too."],"focus":["precision","clarity"]},
    {"id":"precision-fin-early-14","level":"early","profession":"finance","title":"The reconciliation, evidenced","scenario":"You tell your manager the intercompany balance is \"reconciled and fine.\" She's accountable for signing it. 'Fine' isn't evidence — she needs to know it was matched to the counterparty confirmation, with one $300 timing difference explained.","task":"Rewrite the status to show the evidence, not just the verdict.","tips":["State what you matched it against — the counterparty confirmation.","Name the one residual and why it's benign — a timing difference.","'Reconciled' is a claim; the confirmation match is the proof."],"focus":["precision","impact"],"placeholder":"Intercompany matches the counterparty confirmation to the dollar, except a $300 timing item clearing next week —"},
    {"id":"precision-fin-early-15","level":"early","profession":"finance","title":"From 'a few complaints' to a count","scenario":"You're flagging that the new expense system is causing problems: \"a few people have complained\" and \"it seems buggy.\" To get it prioritized, you need the actual scope: 14 tickets in two weeks, all on the same receipt-upload step.","task":"Rewrite the flag with the count, the timeframe, and the specific failure point.","tips":["'A few' → the actual ticket count and window.","Pinpoint the failure — one step, not the whole system.","A specific, counted problem gets fixed; a vague one gets filed."],"focus":["precision","impact"]},
    {"id":"precision-fin-early-16","level":"early","profession":"finance","title":"The forecast miss, sized honestly","scenario":"Revenue came in below forecast and your draft says it was \"a bit light.\" Leadership will read the actual report and see the gap was $340K, or 9%. 'A bit light' will look like you either missed it or spun it.","task":"Rewrite the sentence stating the miss precisely and one honest cause.","tips":["Size the miss in dollars and percent — don't soften it.","Attach the primary cause you can defend.","Underselling a miss costs you credibility on the next forecast."],"focus":["precision","impact"],"placeholder":"Revenue came in $340K (9%) below forecast, driven by two Q2 deals slipping to Q3 —"},
    {"id":"precision-fin-early-17","level":"early","profession":"finance","title":"The assumption made explicit","scenario":"Your headcount cost projection assumes new hires start on their planned dates, but you didn't say so. If three of them slip a month, the number is $40K lower. The reader is treating your figure as certain when it rests on a dated assumption.","task":"Write the one sentence that surfaces the key assumption and its dollar sensitivity.","tips":["Name the assumption the number depends on most.","Quantify what changes if it breaks.","A stated assumption is precision; a hidden one is a trap."],"focus":["precision","clarity"]},
    {"id":"precision-fin-early-18","level":"early","profession":"finance","title":"The 'roughly right' cash figure","scenario":"The treasurer asks for month-end cash and you say \"roughly $4 million.\" For his liquidity planning, the difference between $3.8M and $4.2M matters. Your ledger says $4.15M. 'Roughly $4M' throws away precision you actually have.","task":"Rewrite the answer at the precision the ledger supports and the reader needs.","tips":["Don't round away accuracy you possess.","Match the decimal places to the decision — treasury wants the real figure.","If it's genuinely an estimate, give the range, not a false single number."],"focus":["precision","audience"],"placeholder":"$4.15M at month end —"},
    {"id":"precision-fin-early-19","level":"early","profession":"finance","title":"Turning the anomaly into a claim","scenario":"You spotted that one cost center's spend spiked and you want to raise it. Your draft says \"something looks off with cost center 4400.\" That's an observation, not a claim. What's off: it ran $12K over on a category that's normally near zero.","task":"Rewrite the flag as a precise, defensible claim, in 2 sentences.","tips":["'Looks off' invites 'so investigate it yourself' — do the work first.","State what's abnormal, by how much, versus its own history.","Offer your best hypothesis for the cause."],"focus":["precision","impact"]},
    {"id":"precision-fin-early-20","level":"early","profession":"finance","title":"The percentage without the base","scenario":"You reported that returns are \"up 50%.\" Alarming — until someone learns it went from 2 units to 3. A percentage on a tiny base misleads. Your manager needs both the percent and the absolute numbers.","task":"Rewrite the sentence so the base is visible and the reader can judge whether it matters.","tips":["A percentage without its base can lie in either direction.","Show the absolute figures alongside the percent.","Then say plainly whether it's material or noise."],"focus":["precision","clarity"],"placeholder":"Returns rose from 2 to 3 units (up 50%, but immaterial at this volume) —"},
    {"id":"precision-fin-early-21","level":"early","profession":"finance","title":"The 'should be fine' liquidity call","scenario":"Asked whether payroll and the tax bill both clear next week, you drafted \"should be fine, cash looks okay.\" The treasurer needs the actual coverage: opening balance, the two outflows, the closing cushion. 'Should be fine' is a hope, not an answer.","task":"Rewrite the answer with the figures that prove it, in 2-3 sentences.","tips":["Show the balance, the outflows, and what's left.","A cushion figure is worth more than the word 'fine'.","If it's tight, say how tight — that's the useful precision."],"focus":["precision","impact"]},
    {"id":"precision-fin-early-22","level":"early","profession":"finance","title":"Data to decision in one line","scenario":"You have a table of overtime by department. Your manager doesn't want the table — she wants the decision it points to. The data says one department drives 60% of overtime and has an open req that's been unfilled for four months.","task":"Write the one sentence that turns the table into a recommendation.","tips":["Skip the tour of the table; state where it points.","Connect the pattern to a cause she can act on — the open req.","End with the implied action: fill the role to cut the overtime."],"focus":["precision","impact"],"placeholder":"One department drives 60% of overtime — it's covering a role that's been open four months —"},
    {"id":"precision-fin-early-23","level":"early","profession":"finance","title":"The confidence level, stated","scenario":"You're giving a bad-debt estimate and you know it's shakier than usual because one large account's status is unclear. Your draft states a single clean number. The reader deserves to know how firm it is and what would sharpen it.","task":"Rewrite the estimate to convey your confidence and what it hinges on, in 2 sentences.","tips":["A false-precise single number oversells shaky work.","Give a range and say which way the risk leans.","Name the one input that would tighten it — the account's status."],"focus":["precision","clarity"]},
    {"id":"precision-fin-early-24","level":"early","profession":"finance","title":"The 'used to be' baseline","scenario":"You want to show that a cost-cutting effort worked. Your draft says spending is \"lower now.\" Lower than when, by how much? The real story: office-supply spend fell from $4.2K/month last year to $2.8K/month, a 33% cut sustained for six months.","task":"Rewrite the claim with the before, the after, and the duration.","tips":["'Lower now' needs a 'than what' and a 'by how much'.","Include the timeframe — a sustained cut beats a one-month dip.","Precise before/after figures make the win undeniable."],"focus":["precision","impact"],"placeholder":"Office-supply spend fell from $4.2K to $2.8K per month — a 33% cut, held for six months —"},
    {"id":"precision-fin-early-25","level":"early","profession":"finance","title":"The catch-all 'timing' excuse","scenario":"Three separate variances in your report are all explained as \"timing.\" One truly is timing; one is a genuine overspend you're hoping to bury; one you haven't actually investigated. A skeptic will test all three and your credibility rides on it.","task":"Rewrite the three explanations so only the real timing item says 'timing', each with evidence.","tips":["'Timing' is true when the cost simply lands in a different month — prove it with the offsetting month.","Don't hide a real overspend under a timing label; name it.","If you haven't investigated one, say 'investigating' — not a false cause."],"focus":["precision","impact"]}
  ],
  "executive-presence": [
    {"id":"presence-fin-early-01","level":"early","profession":"finance","title":"Recommend, don't just present","scenario":"Your manager asked which of two software vendors to pick for the finance team. Your draft lays out both neutrally — features, prices, pros, cons — and stops. She wanted your call, not a menu she has to decide from cold.","task":"Rewrite the close so you name a recommendation and the one reason for it.","tips":["End with 'I'd go with X because...' — a menu makes her do your job.","One decisive reason beats a balanced list.","You can still note the tradeoff, but lead with your pick."],"focus":["impact","structure"],"placeholder":"I'd recommend Vendor A: it's $4K cheaper a year and already integrates with our ERP —"},
    {"id":"presence-fin-early-02","level":"early","profession":"finance","title":"Fact versus your read on it","scenario":"You're reporting that a customer paid 40 days late again. Your draft blends the fact with your interpretation so they're indistinguishable: 'the customer is clearly in trouble and won't pay on time going forward.' Your manager can't tell what you know from what you suspect.","task":"Rewrite so the fact and your judgment are clearly separated, in 2-3 sentences.","tips":["State the fact plainly: paid 40 days late, second time this quarter.","Then flag your read as a read: 'my sense is X, worth watching.'","Owning the line between the two is what presence looks like."],"focus":["precision","impact"]},
    {"id":"presence-fin-early-03","level":"early","profession":"finance","title":"Signpost the update","scenario":"You're giving a 90-second verbal close update in the team standup. Your instinct is to start talking and hope it lands. Presence comes from telling them the shape first: 'Two things — one on track, one needs a decision.'","task":"Write the opening signpost sentence and the two labeled points that follow.","tips":["Tell them how many points and their nature before diving in.","Label each so they can follow: 'first, the good news... second, the ask.'","A signposted update sounds in control; a rambling one doesn't."],"focus":["structure","impact"],"placeholder":"Two quick things: the close is on track for day 5, and I need one decision on an accrual —"},
    {"id":"presence-fin-early-04","level":"early","profession":"finance","title":"Owning the number you're unsure of","scenario":"In the budget meeting the director will ask about a projection you're only 70% confident in. Your instinct is to over-qualify until it sounds worthless. Presence is stating it with appropriate confidence and owning the uncertainty cleanly.","task":"Script how you'd deliver the projection aloud — confident, with the uncertainty owned once, not five times.","tips":["State the number as your best estimate, not an apology.","Own the uncertainty in one clean clause, then move on.","Endless hedging reads as not knowing your own work."],"focus":["impact","precision"]},
    {"id":"presence-fin-early-05","level":"early","profession":"finance","title":"The recommendation with a spine","scenario":"You think the department should defer a non-urgent $30K purchase given the cash squeeze. Your draft asks 'do you think maybe we could possibly hold off?' It sounds like you're seeking permission to have an opinion.","task":"Rewrite as a clear recommendation you stand behind, 2 sentences.","tips":["'I recommend we defer the $30K purchase to Q4' — not 'do you think maybe.'","Give the reason that makes it defensible.","You can be junior and still recommend; the seniority is in the reasoning."],"focus":["impact","clarity"],"placeholder":"I'd recommend deferring the $30K equipment purchase to Q4 given the cash timing —"},
    {"id":"presence-fin-early-06","level":"early","profession":"finance","title":"The status that projects control","scenario":"Close is slightly behind and you're anxious. Your draft update is a spiral of caveats and worry. Presence means reporting the reality plainly, owning the one problem, and stating your plan — without the anxiety leaking through.","task":"Write a 3-sentence update: where things stand, the one issue, your plan to fix it.","tips":["Report the state factually, good or bad, without spin or dread.","Own the problem as yours to solve, and say how.","Calm and specific beats anxious and vague — even when behind."],"focus":["impact","structure"]},
    {"id":"presence-fin-early-07","level":"early","profession":"finance","title":"From 'I think' to 'the data shows'","scenario":"You're presenting a spending trend and every sentence starts with 'I think' or 'it seems like.' The analysis is solid, but the framing makes it sound like a hunch. Where the data is firm, speak from the data, not your feelings.","task":"Rewrite three claims moving from 'I think' to what the evidence actually establishes.","tips":["Reserve 'I think' for genuine judgment; use 'the data shows' for facts.","'Spend is up 12%' is stronger than 'I think spend might be up.'","Confidence should track your evidence, not shrink below it."],"focus":["precision","impact"]},
    {"id":"presence-fin-early-08","level":"early","profession":"finance","title":"Disagreeing with a senior, with presence","scenario":"The controller wants to book a receivable you believe isn't collectible yet. You think she's wrong but you're junior. Presence is disagreeing respectfully and substantively — not caving, and not grandstanding.","task":"Write a 2-3 sentence message that states your concern with evidence and defers the decision to her.","tips":["State the concern as a fact-based question, not a challenge.","Give the specific reason — the customer's payment history.","Close by acknowledging it's her call, having made yours honestly."],"focus":["impact","audience"],"placeholder":"Before we book it, one flag: this customer is 90 days past due on the last two invoices —"},
    {"id":"presence-fin-early-09","level":"early","profession":"finance","title":"The ask, made as a peer","scenario":"You need the sales ops lead to change how he tags deals so your commission accrual stops breaking. Your draft is so deferential it sounds like begging. Presence is asking as an equal solving a shared problem.","task":"Rewrite the ask so it's respectful but not subservient, framing it as a mutual fix.","tips":["Frame it as a shared problem, not a favor you're pleading for.","State what you need clearly, without three layers of apology.","Peers ask directly; the subservience undercuts you."],"focus":["impact","audience"]},
    {"id":"presence-fin-early-10","level":"early","profession":"finance","title":"The one-slide recommendation","scenario":"You have one slide in your manager's deck to the CFO about consolidating three bank accounts. Your draft slide is a wall of analysis with no conclusion. The slide should state the recommendation as its title and let the analysis support it.","task":"Write the assertion-style slide title and the one-line recommendation beneath it.","tips":["The title is the recommendation, not the topic: 'Consolidate to one account, save $6K/year.'","Presence is putting the conclusion where the eye lands first.","Analysis supports the claim; it doesn't replace it."],"focus":["impact","structure"],"placeholder":"Consolidate three accounts into one — cuts $6K in annual fees and simplifies reconciliation"},
    {"id":"presence-fin-early-11","level":"early","profession":"finance","title":"Answering 'what do you think?'","scenario":"In a review your manager turns to you: 'You built the model — what do you actually think we should do?' You freeze and start describing the model again. She's asking for your judgment, and presence is having one ready.","task":"Script a 2-3 sentence answer that gives your view and the reason, not a recap.","tips":["She asked what you think — so lead with what you think.","Back it with the one insight from the model that drives your view.","Recapping the model dodges the question; answer it."],"focus":["impact","clarity"]},
    {"id":"presence-fin-early-12","level":"early","profession":"finance","title":"The confident correction of your own error","scenario":"You sent a report with a wrong number and caught it yourself. Your instinct is a groveling, over-long apology. Presence is a clean correction: what was wrong, the right figure, what you've done to prevent it.","task":"Write a 3-sentence correction that owns the error without collapsing.","tips":["State the error and the correct number plainly, once.","One line of accountability, not five of apology.","End on the fix — a check you've added — which restores trust."],"focus":["impact","structure"],"placeholder":"Correction: the OpEx figure should be $412K, not $421K — I transposed two digits. I've added a second review on the flash report to catch this."},
    {"id":"presence-fin-early-13","level":"early","profession":"finance","title":"The neutral menu that dodges","scenario":"Asked how to handle a stale $5K prepaid balance, you offer three options with equal weight and no recommendation. Offering choices without a view isn't neutrality — it's dodging the judgment you're paid for.","task":"Rewrite to present the options but end with your recommended one and why.","tips":["List the options briefly, then commit to one.","'Of these, I'd write it off — it's below threshold and the vendor's gone.'","A recommendation you can defend shows presence; a menu hides.","Let them overrule you; don't pre-empt yourself into silence."],"focus":["impact","structure"]},
    {"id":"presence-fin-early-14","level":"early","profession":"finance","title":"Presence in the room, not just the deck","scenario":"You're presenting your first analysis to the leadership team. Your slides are strong but you plan to read them aloud, eyes down. Presence is delivering the headline looking up, and letting the slide be the backup.","task":"Write the two-sentence spoken opening you'd say while looking at the room, not the screen.","tips":["Say the conclusion to the people, not the projector.","The slide reinforces you; you don't narrate the slide.","Open with the finding they need, then invite them to the detail."],"focus":["impact","audience"]},
    {"id":"presence-fin-early-15","level":"early","profession":"finance","title":"Standing behind the flag you raised","scenario":"You flagged a control weakness and now a manager is pushing back, half-hoping you'll drop it. Presence is holding the position with evidence, not folding because someone senior frowned.","task":"Write a 2-3 sentence reply that holds the flag calmly and restates the evidence.","tips":["Acknowledge the pushback without conceding the point.","Restate the specific evidence, not just your opinion.","Offer a path forward that keeps the control intact."],"focus":["impact","precision"]},
    {"id":"presence-fin-early-16","level":"early","profession":"finance","title":"The proactive heads-up","scenario":"You can see a problem forming three weeks out — a vendor contract auto-renews at a higher rate unless someone acts. You could wait to be asked, or you could raise it now with a recommendation. Presence is bringing the issue before it's a fire.","task":"Write a 2-3 sentence proactive note: the coming issue, the deadline, your recommended action.","tips":["Lead with the deadline that creates urgency.","Don't just report the problem — bring the recommended action.","Being early and solution-ready is what presence looks like from a junior."],"focus":["impact","structure"],"placeholder":"Heads-up: the CloudSoft contract auto-renews July 30 at a 20% higher rate unless we act — I'd recommend we renegotiate now —"},
    {"id":"presence-fin-early-17","level":"early","profession":"finance","title":"Separating the number from the narrative","scenario":"You're reporting that costs beat budget, and you're tempted to add spin — 'great result, team's really tightened up.' The number is the fact; whether it's 'great' is a judgment that may not hold. Keep them separate so both stay credible.","task":"Rewrite so the factual result and any interpretation are clearly distinct.","tips":["State the number as fact: costs 3% under budget.","If you add a read, mark it as yours and keep it measured.","Spin blended into facts contaminates the facts."],"focus":["precision","impact"]},
    {"id":"presence-fin-early-18","level":"early","profession":"finance","title":"The confident 'here's what I need'","scenario":"To finish the analysis on time you need two things from your manager: a decision and an introduction to the ops lead. Your draft buries these in hopeful hints. Presence is stating your needs plainly as a professional who knows what the work requires.","task":"Write a 2-sentence message stating exactly what you need and by when.","tips":["Name the two things directly — a decision and an intro.","Give the deadline; presence includes respecting the timeline.","Clear asks from a junior read as competence, not demands."],"focus":["impact","clarity"]},
    {"id":"presence-fin-early-19","level":"early","profession":"finance","title":"Not apologizing for good work","scenario":"You're sharing a solid variance analysis and your cover note opens 'sorry, this is probably too detailed and might not be what you wanted.' You've apologized for competent work before anyone read it. Presence is offering it with quiet confidence.","task":"Rewrite the cover note opening without the pre-emptive apology.","tips":["Cut the apology; the work stands on its own.","Say what it is and where the key finding sits.","Invite feedback without begging for forgiveness."],"focus":["impact","concision"],"placeholder":"Here's the variance analysis — the one thing to note is on page 2:"},
    {"id":"presence-fin-early-20","level":"early","profession":"finance","title":"The measured response to praise and to critique","scenario":"Your manager praises one part of your report and criticizes another in the same breath. Your draft over-thanks for the praise and over-defends against the critique. Presence is receiving both evenly and moving to the substance.","task":"Write a 2-3 sentence reply that takes the praise gracefully and the critique constructively.","tips":["A brief thanks, not a paragraph of gratitude.","Engage the critique with a fix, not a defense.","Even footing on both signals maturity."],"focus":["impact","audience"]},
    {"id":"presence-fin-early-21","level":"early","profession":"finance","title":"The clear position in a debate","scenario":"Two managers disagree in a meeting about whether a cost belongs to marketing or sales, and both look to you for the finance answer. Presence is stating where it belongs and why, cleanly, rather than hedging to avoid displeasing either.","task":"Script a 2-3 sentence answer that gives the finance position with its basis.","tips":["Give the answer, don't split it to keep everyone happy.","Ground it in the rule — where the benefit accrues, the cost goes.","You can be diplomatic and still be definite."],"focus":["impact","precision"],"placeholder":"It belongs to marketing — the campaign drove the spend, so it lands in their cost center per our allocation rule —"},
    {"id":"presence-fin-early-22","level":"early","profession":"finance","title":"The one-line executive summary","scenario":"Your five-page cost review is going to the VP, who will read one paragraph. Your draft summary is a hedge-laden recap. Presence is a summary that states the conclusion and the one decision it implies, first.","task":"Write the 2-3 sentence executive summary that leads with the conclusion and the ask.","tips":["Conclusion first — the VP reads no further than this.","One implied decision, stated as your recommendation.","The five pages are evidence; the summary is your judgment."],"focus":["impact","structure"]},
    {"id":"presence-fin-early-23","level":"early","profession":"finance","title":"Holding the floor when interrupted","scenario":"You're mid-answer in a review and a senior manager talks over you with a wrong assumption. Presence is finishing your point calmly and correcting the assumption without either backing down or bristling.","task":"Script how you'd reclaim the point and correct the assumption in 2 sentences.","tips":["Acknowledge briefly, then return to your point — don't just yield.","Correct the assumption with a fact, not a tone.","Composure under interruption is presence you can practice."],"focus":["impact","audience"]},
    {"id":"presence-fin-early-24","level":"early","profession":"finance","title":"The recommendation under uncertainty","scenario":"Your manager needs a call on whether to accrue for a possible penalty, and the information is incomplete. Presence isn't waiting for certainty that won't come — it's recommending under uncertainty and stating what would change your mind.","task":"Write a 2-3 sentence recommendation that commits despite incomplete data, with the trigger to revisit.","tips":["Make the call your best judgment supports now.","State the assumption it rests on.","Name what new information would flip it — that's presence, not waffling."],"focus":["impact","precision"],"placeholder":"I'd accrue $10K now as our best estimate — if the vendor confirms the fee is waived, we reverse it —"},
    {"id":"presence-fin-early-25","level":"early","profession":"finance","title":"Closing with the decision, not the discussion","scenario":"Your email walked through a reconciliation issue thoroughly, but it ends open — 'let me know your thoughts.' You've done the analysis; presence is closing with the decision you're recommending and the specific next step.","task":"Rewrite the closing to end on your recommendation and a concrete next action.","tips":["'Let me know your thoughts' hands back a problem you could close.","End with what you recommend and what you'll do if approved.","A clear next step shows you're driving, not just reporting."],"focus":["impact","clarity"],"placeholder":"My recommendation is to post the correcting entry today — I'll do it as soon as you confirm —"}
  ],
  "answering-under-pressure": [
    {"id":"pressure-fin-early-01","level":"early","profession":"finance","title":"Answer the question they asked","scenario":"In the budget review the director asks: 'Is the marketing overspend a one-time thing or will it recur?' You start explaining how you calculated the variance. She interrupts — she asked one-time or recurring, and you dodged it.","task":"Answer the actual question in the first sentence, then support it.","tips":["One-time or recurring — pick one and say it first.","The calculation is support, not the answer to her question.","Answer, then explain; never explain instead of answering."],"focus":["clarity","impact"],"placeholder":"One-time — it's a Q2 campaign that ran early; the run-rate returns to plan in July —"},
    {"id":"pressure-fin-early-02","level":"early","profession":"finance","title":"The honest 'I don't know' with a path","scenario":"In a meeting the controller asks why a specific accrual is $8K higher than last month. You don't know off the top of your head. The wrong move is to guess or bluff; the right one is honest, with a commitment to find out.","task":"Script a 2-sentence answer: honest that you don't know, plus when you'll have it.","tips":["Say 'I don't know yet' cleanly — no waffling to fake it.","Attach a path: 'I'll trace it and confirm by end of day.'","A confident 'I don't know, here's how I'll find out' beats a wrong guess."],"focus":["clarity","impact"],"placeholder":"I don't know off-hand, but I'll trace the driver and have it to you by 2pm —"},
    {"id":"pressure-fin-early-03","level":"early","profession":"finance","title":"Pushback with specifics, not defense","scenario":"The sales director challenges your commission accrual: 'This is way too low, my team closed a huge month.' Your instinct is to defend your process. What works is specifics — the accrual reflects the 14 deals that met the recognition criteria, not the 6 still pending.","task":"Write a 2-3 sentence reply that answers with the specific facts, not a defense of yourself.","tips":["Don't defend your competence; present the numbers.","Name the exact rule that explains the figure.","Specifics defuse; defensiveness escalates."],"focus":["precision","impact"]},
    {"id":"pressure-fin-early-04","level":"early","profession":"finance","title":"The loaded question in the standup","scenario":"Your manager asks in front of the team: 'Why is close running late again?' The 'again' is a trap that invites a defensive spiral. Answer the substance — the actual cause and the fix — without taking the bait.","task":"Script a calm 2-3 sentence answer that addresses the cause and the fix, not the 'again.'","tips":["Ignore the sting; answer the legitimate question inside it.","State the cause factually and the corrective step.","Composure here reads as competence to the whole team."],"focus":["impact","clarity"]},
    {"id":"pressure-fin-early-05","level":"early","profession":"finance","title":"When you're asked to speculate","scenario":"The VP asks whether Q3 will hit target. It's only mid-Q2; you genuinely can't know. The pressure is to give a confident yes. The skill is answering usefully without pretending to a certainty you don't have.","task":"Write a 2-3 sentence answer that gives what you can honestly say and flags what you can't.","tips":["Say what the current data supports, bounded honestly.","Distinguish the known from the genuinely uncertain.","Name the milestone that will make the answer knowable."],"focus":["precision","impact"],"placeholder":"Too early to commit, but Q2 is tracking to plan and the pipeline supports Q3 — I'll know more after the June forecast —"},
    {"id":"pressure-fin-early-06","level":"early","profession":"finance","title":"The 'just give me a number' demand","scenario":"A manager wants a single savings figure now for a decision, but your analysis has a real range depending on assumptions. He's impatient and pressing. You need to give something usable without abandoning the honesty of the range.","task":"Write a 2-sentence answer that gives a point estimate and its key caveat, respecting his time.","tips":["Give the number he's asking for — your best single estimate.","Attach the one assumption that moves it most.","Refusing to answer frustrates; a caveated number serves him."],"focus":["precision","impact"]},
    {"id":"pressure-fin-early-07","level":"early","profession":"finance","title":"Challenged on your own error, live","scenario":"In the meeting someone points out a mistake in your report — a real one. All eyes turn to you. The pressure pulls toward minimizing or deflecting; the skill is owning it fast and moving to the fix.","task":"Script a 2-sentence response that owns the error and states what changes because of it.","tips":["Acknowledge it immediately — no minimizing, no deflecting.","Say what the corrected picture is or when you'll have it.","Owning an error under pressure builds more trust than being right."],"focus":["impact","clarity"]},
    {"id":"pressure-fin-early-08","level":"early","profession":"finance","title":"The question you can't answer without breaking confidence","scenario":"In an open meeting someone asks you a compensation-related number you know but shouldn't disclose there. The pressure is to answer helpfully. The skill is declining cleanly without being evasive or rude.","task":"Script a 2-sentence answer that declines appropriately and offers the right channel.","tips":["Decline plainly and say why — it's confidential, not that you don't know.","Offer the proper route: 'happy to cover it with you and HR directly.'","A clean boundary reads as professional, not obstructive."],"focus":["clarity","audience"]},
    {"id":"pressure-fin-early-09","level":"early","profession":"finance","title":"Rapid-fire follow-ups","scenario":"You give one answer in the review and the director fires three follow-ups in a row, each sharper. The pressure is to rush and blur. The skill is answering each one directly and briefly, not merging them into mush.","task":"Given three follow-ups (why up, is it recurring, what's the fix), write one crisp sentence answering each.","tips":["Answer each question as its own unit — don't blend them.","One sentence each keeps you sharp under fire.","Pausing to answer cleanly beats rushing to answer vaguely."],"focus":["clarity","concision"]},
    {"id":"pressure-fin-early-10","level":"early","profession":"finance","title":"When the premise is wrong","scenario":"A manager asks, 'Why did finance cut my travel budget?' Finance didn't — his own VP reallocated it. The pressure is to answer the question as asked; the skill is correcting the false premise gently before answering.","task":"Write a 2-3 sentence reply that corrects the premise and gives the real answer.","tips":["Fix the premise first, without making him wrong for asking.","Then give the actual cause and who to talk to.","Answering a false-premise question directly spreads the error."],"focus":["clarity","audience"],"placeholder":"Finance didn't cut it — your VP reallocated $10K to headcount in the last planning round —"},
    {"id":"pressure-fin-early-11","level":"early","profession":"finance","title":"The skeptic who doubts your data","scenario":"A manager says flatly, 'I don't believe these numbers.' The pressure is to get defensive about your work. The skill is inviting the challenge and grounding the number in its source so the doubt has somewhere to go.","task":"Write a 2-3 sentence reply that stays open and points to the verifiable source.","tips":["Don't take it personally; treat it as a request for evidence.","Name the source and offer to walk through the derivation.","Confidence plus transparency dissolves most skepticism."],"focus":["impact","precision"]},
    {"id":"pressure-fin-early-12","level":"early","profession":"finance","title":"Put on the spot in someone else's meeting","scenario":"You're sitting in on a meeting and a director suddenly asks your view on a cash decision you weren't prepped for. The pressure is to say something impressive. The skill is giving a measured answer within what you actually know.","task":"Script a 2-sentence answer that offers a grounded view and flags where you'd need to check.","tips":["Answer from what you genuinely know, not what sounds good.","Draw the line: 'On the cash side, X; on the tax side, I'd need to check.'","A bounded honest answer beats an overconfident wrong one."],"focus":["impact","precision"]},
    {"id":"pressure-fin-early-13","level":"early","profession":"finance","title":"The 'can you just make it work?' pressure","scenario":"A manager wants you to book revenue in a period it doesn't belong to so his quarter looks better. The pressure is real and he's senior. The skill is declining clearly on the substance without lecturing or panicking.","task":"Write a 2-3 sentence reply that says no on the merits and offers what you legitimately can do.","tips":["Say no clearly, grounded in the rule, not in your discomfort.","Explain the reason briefly — recognition criteria, not opinion.","Offer the legitimate alternative so it's not just a wall."],"focus":["impact","clarity"],"placeholder":"I can't move it into Q2 — the service wasn't delivered until July, so it recognizes then. What I can do is —"},
    {"id":"pressure-fin-early-14","level":"early","profession":"finance","title":"Interrogated on an assumption","scenario":"In the forecast review, someone zeroes in: 'Why did you assume 5% price growth?' It's a fair challenge and you have a reason. The pressure is to over-defend; the skill is giving the basis calmly and conceding the uncertainty honestly.","task":"Write a 2-3 sentence answer that gives the basis for the assumption and its sensitivity.","tips":["State where the 5% came from — a source or a decision.","Own that it's an assumption, and show what happens if it's off.","Defending an assumption with evidence, not stubbornness, is the skill."],"focus":["precision","impact"]},
    {"id":"pressure-fin-early-15","level":"early","profession":"finance","title":"The angry vendor call escalated to you","scenario":"A vendor is on the phone, furious about a late payment, and it's been handed to you. The pressure is to promise anything to make it stop. The skill is acknowledging, giving only what you can verify, and committing to a real next step.","task":"Script a 2-3 sentence response that de-escalates without over-promising.","tips":["Acknowledge the frustration before any facts.","Commit only to what you can actually confirm.","A real date beats a vague reassurance that breaks tomorrow."],"focus":["audience","impact"]},
    {"id":"pressure-fin-early-16","level":"early","profession":"finance","title":"When you need to buy time honestly","scenario":"The CFO's office asks for a number in the meeting and you can't verify it on the spot. The pressure is to blurt an estimate. The skill is buying time honestly — committing to a fast, accurate answer rather than a fast, wrong one.","task":"Write a 2-sentence reply that declines to guess and commits to a specific fast turnaround.","tips":["Don't guess a number that will be quoted as fact.","Commit to a short, specific turnaround — 'by 3pm, confirmed.'","Accuracy on a number the CFO uses matters more than speed."],"focus":["precision","clarity"],"placeholder":"I want to give you a number I can stand behind — let me confirm it and get it to you by 3pm —"},
    {"id":"pressure-fin-early-17","level":"early","profession":"finance","title":"The 'why didn't you catch this?' question","scenario":"A discrepancy slipped through and a manager asks pointedly why you didn't catch it. The pressure is to make excuses. The skill is a straight answer about the gap and the control you're adding, without either grovel or blame.","task":"Write a 2-3 sentence answer that explains the gap factually and names the fix.","tips":["Explain how it slipped without excuse-making or blaming others.","Move fast to the control that prevents a repeat.","Forward-looking accountability lands better than backward defense."],"focus":["impact","clarity"]},
    {"id":"pressure-fin-early-18","level":"early","profession":"finance","title":"The hostile 'that's not my problem' response","scenario":"You ask a department head for overdue data and he snaps 'that's finance's job, not mine.' The pressure is to snap back or cave. The skill is holding the ask calmly and clarifying why it genuinely needs him.","task":"Write a 2-3 sentence reply that stays professional and re-anchors the ask in what only he has.","tips":["Don't match the hostility; stay level.","Clarify why the data must come from him specifically.","Make it easy — offer to do the rest once he provides the one piece."],"focus":["audience","impact"]},
    {"id":"pressure-fin-early-19","level":"early","profession":"finance","title":"The question with a hidden agenda","scenario":"A manager asks a seemingly innocent question about the allocation method — but you sense he's building a case to shift costs off his budget. The skill is answering the actual question honestly while not being maneuvered into agreeing to something.","task":"Write a 2-3 sentence answer that responds honestly but doesn't concede the unstated ask.","tips":["Answer what's literally asked, accurately.","Don't volunteer agreement to the move you sense coming.","If the real ask surfaces, address it directly then."],"focus":["clarity","impact"]},
    {"id":"pressure-fin-early-20","level":"early","profession":"finance","title":"Staying precise when rushed","scenario":"The controller is walking out the door and asks over her shoulder for the AR total. You're tempted to round wildly to answer fast. The skill is being both quick and accurate — the real figure, not a panicked approximation.","task":"Write the one-line answer that is fast and precise.","tips":["Speed and accuracy aren't opposed — you know this number.","Give the real figure, not a nervous round number.","If you truly don't have it, say when you will, in the same breath."],"focus":["precision","concision"],"placeholder":"AR is $1.84M, with $210K overdue —"},
    {"id":"pressure-fin-early-21","level":"early","profession":"finance","title":"The follow-up that exposes a gap","scenario":"You answered confidently, then the next question reveals you didn't consider something. The pressure is to bluff through. The skill is acknowledging the gap immediately and adjusting, rather than defending a now-shaky answer.","task":"Script a 2-sentence response that concedes the point and updates your answer.","tips":["Concede fast: 'Good point — I hadn't factored that.'","Update the answer honestly rather than defending the old one.","Adjusting gracefully under pressure builds credibility."],"focus":["impact","clarity"]},
    {"id":"pressure-fin-early-22","level":"early","profession":"finance","title":"Asked to defend a decision that wasn't yours","scenario":"A manager demands to know why a cost was allocated a certain way — a policy set above you. The pressure is to either own it defensively or throw the policy-setter under the bus. The skill is explaining the rationale and routing the real challenge correctly.","task":"Write a 2-3 sentence reply that explains the policy's logic and points to where a change would be decided.","tips":["Explain the reasoning behind the policy neutrally.","Don't defend it as if it were your personal call.","Point to the right forum if he wants to challenge it."],"focus":["clarity","audience"]},
    {"id":"pressure-fin-early-23","level":"early","profession":"finance","title":"The 'yes or no' that isn't","scenario":"A director demands a yes/no on whether the department will hit budget, but the honest answer is 'yes, unless the pending contract closes.' The pressure is to pick a clean yes or no. The skill is giving the direct lead answer plus the one real condition.","task":"Write a 2-sentence answer that leads with the direct answer and states the one condition.","tips":["Lead with the closest thing to yes/no that's true.","State the single condition that could change it.","A conditional answer given clearly still counts as answering."],"focus":["clarity","precision"],"placeholder":"Yes — on budget, with one condition: if the delayed vendor contract signs this month, we go $15K over —"},
    {"id":"pressure-fin-early-24","level":"early","profession":"finance","title":"Keeping composure when blamed unfairly","scenario":"A project ran over and a manager pins it on 'finance being slow to approve.' You know the delay was his incomplete paperwork, but he's saying it to leadership. The skill is correcting the record with facts, calmly, without a counterattack.","task":"Write a 2-3 sentence reply that sets the record straight with specifics, not accusation.","tips":["Correct with dates and facts, not blame.","'Approvals cleared same-day once the PO was complete on the 12th.'","Let the timeline make your case; keep your tone even."],"focus":["precision","impact"]},
    {"id":"pressure-fin-early-25","level":"early","profession":"finance","title":"The follow-up you should have anticipated","scenario":"You present a cost saving and the obvious question comes — 'what did it cost to achieve it?' — and you're caught flat. The skill under pressure is a composed 'let me get you that' plus, ideally, having anticipated it in the first place.","task":"Script a 2-sentence response that handles being caught out and commits to the missing piece.","tips":["Don't invent the net figure — you'll be quoted on it.","Acknowledge it's the right question and commit to the answer.","Next time, pre-answer the obvious follow-up in the first pass."],"focus":["impact","precision"]}
  ],
  "narrative-and-persuasion": [
    {"id":"narrative-fin-early-01","level":"early","profession":"finance","title":"Before and after the automation","scenario":"You want the controller to fund a $5K tool that automates your reconciliation. A flat feature list won't move her. The persuasion is in the contrast: today it's six manual hours and two errors a quarter; after, it's twenty minutes and a full audit trail.","task":"Write a 3-4 sentence pitch built on the before/after contrast.","tips":["Paint 'before' concretely — the hours, the errors, the risk.","Make 'after' the same picture, transformed.","The gap between the two is the argument; the tool is the bridge."],"focus":["impact","structure"],"placeholder":"Today the card rec takes six hours and produced two errors last quarter. With this tool it's twenty minutes and a clean audit trail —"},
    {"id":"narrative-fin-early-02","level":"early","profession":"finance","title":"Making the cash risk concrete","scenario":"You need leadership to take a slow-paying customer seriously, but 'DSO is rising' is abstract. Make the stakes concrete: this one customer owes $180K, 75 days late, and if they default it wipes out the quarter's margin cushion.","task":"Write a 2-3 sentence flag that makes the stake vivid and specific.","tips":["Turn the ratio into a real dollar amount and a real customer.","Connect it to something leadership feels — the margin cushion.","Concrete stakes get action; abstract metrics get filed."],"focus":["impact","precision"]},
    {"id":"narrative-fin-early-03","level":"early","profession":"finance","title":"Pre-empt the strongest objection","scenario":"You're proposing to cut a rarely-used software license to save $8K. The strongest objection is obvious: 'but the two people who use it will be blocked.' If you ignore it, you lose. If you name and answer it first, you win.","task":"Write a 3-4 sentence proposal that raises the strongest objection yourself and answers it.","tips":["Name the objection before they do — it disarms them.","Answer it with a concrete plan for the affected users.","Un-addressed, the objection kills the idea; addressed, it validates you."],"focus":["impact","structure"],"placeholder":"Cutting the license saves $8K. The fair objection is the two active users — I've confirmed the free tier covers their usage, so no one loses access —"},
    {"id":"narrative-fin-early-04","level":"early","profession":"finance","title":"The story behind the variance","scenario":"Your variance report is a list of numbers, and leadership's eyes glaze. The same facts as a short narrative land: 'we planned conservatively, sales beat plan, so commissions ran high — a good problem, not a control failure.' Frame the numbers, don't just state them.","task":"Rewrite the variance as a 3-sentence narrative that gives the numbers meaning.","tips":["A number list has no cause-and-effect; a narrative does.","Lead with the story: what happened and why it's the right kind of over.","The framing changes how the same overspend is received."],"focus":["structure","impact"]},
    {"id":"narrative-fin-early-05","level":"early","profession":"finance","title":"Selling the process change to the team","scenario":"You want the team to adopt a new expense-coding step that adds work for them but saves finance hours at close. The persuasion isn't 'it helps me' — it's showing them what they get: fewer rejected reports and faster reimbursement.","task":"Write a 3-sentence pitch framed around the team's benefit, not finance's.","tips":["Lead with what changes for them, not for you.","'Fewer rejections, faster reimbursement' is their win.","People adopt changes that help them; frame accordingly."],"focus":["audience","impact"]},
    {"id":"narrative-fin-early-06","level":"early","profession":"finance","title":"The capex case as a story","scenario":"The old delivery van costs more to repair every month and finance is asked to support replacing it. The winning case isn't a spec sheet — it's the trajectory: repairs were $200/month two years ago, they're $900 now, and the curve crosses the purchase price within a year.","task":"Write a 3-4 sentence narrative that uses the rising-cost trajectory to make replacement feel inevitable.","tips":["Tell the trend as a story with a direction, not a static number.","Show the crossover point where repairing costs more than replacing.","Let the arithmetic make the decision feel obvious."],"focus":["impact","precision"]},
    {"id":"narrative-fin-early-07","level":"early","profession":"finance","title":"Framing a 'no' as a redirect","scenario":"A manager wants to spend on a nice-to-have while the department is over budget. Flat refusal breeds resentment. The persuasive frame acknowledges the goal and redirects to how it becomes affordable — do it next quarter when the timing budget frees up.","task":"Write a 3-sentence reply that validates the goal and reframes toward when it works.","tips":["Acknowledge the goal as legitimate before the constraint.","Frame the timing, not the idea, as the problem.","A 'not now, here's when' persuades better than a flat 'no.'"],"focus":["audience","impact"]},
    {"id":"narrative-fin-early-08","level":"early","profession":"finance","title":"Concrete stakes for the control gap","scenario":"You found that anyone can approve their own expense reports — a control gap. 'It's a segregation-of-duties issue' means nothing to non-finance leaders. Make it concrete: someone could approve their own $10K claim and no one would catch it until audit.","task":"Write a 2-3 sentence flag that makes the risk tangible with a plausible scenario.","tips":["Replace the jargon with a scenario a leader can picture.","Use a concrete, plausible number and outcome.","The scenario is the persuasion; the control term is just the label."],"focus":["impact","clarity"]},
    {"id":"narrative-fin-early-09","level":"early","profession":"finance","title":"The 'why now' urgency","scenario":"You've wanted to clean up the chart of accounts for months and finally have a case. But 'it would be nice' won't get resources. The persuasion is the trigger: the ERP upgrade next quarter is the one cheap window to do it, and after that it's a costly project.","task":"Write a 3-sentence pitch that ties the cleanup to a 'why now' that creates urgency.","tips":["A good idea without urgency gets deferred forever.","Anchor to the window that makes now the cheap moment.","'If we don't do it during the upgrade, it becomes a project' is the lever."],"focus":["impact","structure"]},
    {"id":"narrative-fin-early-10","level":"early","profession":"finance","title":"Persuading with the peer comparison","scenario":"You want the department to tighten its travel policy, which is looser than the rest of the company. The persuasion isn't 'travel is high' — it's that this department spends 40% more per head than comparable teams, with no better result to show for it.","task":"Write a 2-3 sentence case built on the peer comparison.","tips":["A comparison to peers is more persuasive than a raw number.","Show the gap and that it buys nothing extra.","Comparison creates the discomfort that motivates change."],"focus":["impact","precision"],"placeholder":"This team spends 40% more per head on travel than comparable groups, with no difference in outcomes —"},
    {"id":"narrative-fin-early-11","level":"early","profession":"finance","title":"The two-path narrative","scenario":"Leadership must decide whether to collect aggressively on a big overdue account or preserve the relationship. You can persuade by laying out two clear paths with their consequences, rather than pushing one blindly. Frame it as a genuine choice with an implied lean.","task":"Write a 3-4 sentence framing of the two paths and their consequences, with your lean.","tips":["Give each path its honest upside and cost.","A fair two-path frame earns trust for your recommendation.","End with your lean and why — persuasion, not just presentation."],"focus":["structure","impact"]},
    {"id":"narrative-fin-early-12","level":"early","profession":"finance","title":"Making the intangible saving real","scenario":"Your process fix mostly saves stress and reduces error risk — hard to quantify. To persuade, translate the intangible into something concrete: one avoided error last quarter would have cost $15K to unwind and a day of the controller's time.","task":"Write a 2-3 sentence case that grounds the soft benefit in a concrete cost avoided.","tips":["Anchor the intangible to a real, recent near-miss.","Attach a dollar and time cost to the error avoided.","Soft benefits persuade when tied to a hard number."],"focus":["impact","precision"]},
    {"id":"narrative-fin-early-13","level":"early","profession":"finance","title":"The objection you're tempted to hide","scenario":"Your proposal to switch payroll providers saves money but has one real downside: a painful two-month transition. You're tempted to leave it out. But leaving it for them to discover destroys trust; naming and planning for it is what persuades.","task":"Write a 3-4 sentence pitch that includes the downside and how you'd manage it.","tips":["Volunteering the downside makes the upside believable.","Show you've planned for it, not just noticed it.","A hidden downside found later poisons the whole case."],"focus":["impact","structure"]},
    {"id":"narrative-fin-early-14","level":"early","profession":"finance","title":"Framing the budget cut for morale","scenario":"You have to tell a team their budget is being cut 10%, and how you frame it shapes whether they cooperate. The persuasive frame isn't 'we're taking money away' — it's 'the company protected your headcount by trimming discretionary spend everywhere, including here.'","task":"Write a 3-sentence framing that delivers the cut in a way that preserves goodwill.","tips":["Frame the cut within the larger choice that protected what matters more.","Be honest — don't spin, reframe truthfully.","The same cut lands differently depending on the story around it."],"focus":["audience","impact"]},
    {"id":"narrative-fin-early-15","level":"early","profession":"finance","title":"The one number that tells the whole story","scenario":"You're arguing that the company's discounting is out of control. You could show fifty rows, but the persuasive move is the single number that captures it: average discount rose from 8% to 19% in a year, quietly erasing a third of gross margin.","task":"Write a 2-3 sentence case anchored on that one telling number.","tips":["Find the single statistic that carries the whole argument.","Give it context — from what, to what, over what period.","One vivid number persuades more than fifty rows of support."],"focus":["impact","precision"],"placeholder":"Average discount climbed from 8% to 19% in a year — quietly eating a third of our gross margin —"},
    {"id":"narrative-fin-early-16","level":"early","profession":"finance","title":"Persuading up: getting your manager to escalate","scenario":"A recurring data-quality problem needs a director-level fix, but your manager keeps patching it. To persuade her to escalate, frame the cumulative cost of patching versus the one-time cost of fixing it properly.","task":"Write a 3-sentence case that motivates escalation by contrasting patch cost with fix cost.","tips":["Show the running cost of the status quo, not just the annoyance.","Contrast it with the bounded cost of a real fix.","Make escalation the rational choice, not a complaint."],"focus":["impact","structure"]},
    {"id":"narrative-fin-early-17","level":"early","profession":"finance","title":"The relatable analogy for a dry ask","scenario":"You need budget owners to reconcile their own tracking to the ledger monthly, and they find it tedious. An analogy persuades: it's like checking your bank statement — skip it for months and the surprise at year-end is nobody's friend.","task":"Write a 2-3 sentence pitch that uses a relatable analogy to make the dry task feel worth it.","tips":["A good analogy makes an abstract chore concrete.","Keep it honest and close to their real experience.","The analogy earns the behavior the policy alone can't."],"focus":["audience","impact"]},
    {"id":"narrative-fin-early-18","level":"early","profession":"finance","title":"Building the case with a trend arc","scenario":"You want to warn that a small monthly overspend is becoming a pattern. One month is dismissible. The persuasive arc shows the trajectory: $2K over in Q1, $5K in Q2, $9K trending in Q3 — a line pointing somewhere leadership won't like.","task":"Write a 2-3 sentence warning that uses the trend arc to create concern.","tips":["Three points make a line that a single point can't.","Extend the line to its implication if unchecked.","The arc, not any one number, is what persuades."],"focus":["precision","impact"]},
    {"id":"narrative-fin-early-19","level":"early","profession":"finance","title":"The win worth retelling","scenario":"Your reconciliation cleanup saved real time and caught a real error, but buried in a status update it's invisible. To get the process adopted elsewhere, tell it as a short success story: the problem, what you changed, the concrete result.","task":"Write a 3-sentence success narrative that would make another team want to copy it.","tips":["Structure it as problem, action, result — a mini story.","Lead with the pain others also feel.","End on the specific, repeatable win."],"focus":["structure","impact"]},
    {"id":"narrative-fin-early-20","level":"early","profession":"finance","title":"Pre-empting the 'we've always done it this way'","scenario":"You're proposing to drop a monthly report nobody reads. The predictable objection is 'but we've always produced it.' The persuasive move names that reflex, then shows the report's zero readership and the hours it costs.","task":"Write a 3-sentence proposal that anticipates the tradition objection and answers it with evidence.","tips":["Name the 'we've always done it' reflex before it's spoken.","Counter with the readership data and the cost.","Tradition falls to evidence, not to argument."],"focus":["impact","precision"]},
    {"id":"narrative-fin-early-21","level":"early","profession":"finance","title":"The stakes if nothing changes","scenario":"You want approval to renegotiate a vendor contract before auto-renewal. To persuade, make the do-nothing path concrete: if we let it renew, we're locked into a 20% increase for another year — $30K we can't recover.","task":"Write a 2-3 sentence case that makes the cost of inaction vivid.","tips":["The status quo has a cost; make it visible.","Put a number and a deadline on doing nothing.","'What we lose by not acting' often persuades more than the upside."],"focus":["impact","precision"],"placeholder":"If we let it auto-renew, we're locked into a 20% increase — $30K over the year we can't get back —"},
    {"id":"narrative-fin-early-22","level":"early","profession":"finance","title":"Persuading a peer to prioritize your ask","scenario":"You need the data team to prioritize a report you depend on, but they're swamped and it's not their priority. Persuasion means connecting your ask to something they care about — this report is what unblocks the CFO dashboard they're being asked about.","task":"Write a 2-3 sentence ask that links your need to their existing priority.","tips":["Find where your need intersects their priorities.","Frame it as helping them hit something they're already accountable for.","Shared stakes move a peer faster than a favor request."],"focus":["audience","impact"]},
    {"id":"narrative-fin-early-23","level":"early","profession":"finance","title":"The vivid contrast for a tool upgrade","scenario":"You want to persuade your manager the team has outgrown spreadsheets for the forecast. Abstract complaints won't land. The contrast will: last cycle three people spent two days manually merging tabs, and one broken link caused a $50K error that took a day to find.","task":"Write a 3-4 sentence case built on the vivid, specific pain of the current state.","tips":["Specific pain persuades; general frustration doesn't.","Name the people, the hours, and the error the old way caused.","Let the current-state horror imply the need for change."],"focus":["impact","precision"]},
    {"id":"narrative-fin-early-24","level":"early","profession":"finance","title":"Framing the ask around their goal","scenario":"You want a department head to submit budget inputs on time, and 'it's the deadline' hasn't worked. Reframe around his goal: on-time inputs mean his priorities get funded as he wants; late ones mean finance estimates, usually conservatively.","task":"Write a 2-3 sentence reframe that makes timeliness serve his interest, not just yours.","tips":["Connect the deadline to what he gets out of meeting it.","'Your numbers vs. our estimate' is a real incentive.","Self-interest beats compliance as a motivator."],"focus":["audience","impact"]},
    {"id":"narrative-fin-early-25","level":"early","profession":"finance","title":"The full arc in three sentences","scenario":"You have thirty seconds to pitch your manager on a small process fix. The full persuasive arc — problem, cost of the problem, your solution — has to fit in three sentences that make her want to hear more.","task":"Write the three-sentence pitch: the problem, its cost, your fix.","tips":["Compress the whole arc; every sentence does one job.","Sentence one: the problem. Two: what it costs. Three: the fix.","Leave her wanting the detail, not drowning in it."],"focus":["structure","concision"],"placeholder":"We rekey the same vendor data into two systems every month. It burns four hours and caused last month's mismatch. A one-time export mapping fixes it —"}
  ],
  "delivering-hard-messages": [
    {"id":"hard-fin-early-01","level":"early","profession":"finance","title":"Front-load the bad news","scenario":"You have to tell a department head their project is $50K over and will need a VP sign-off to continue. Your draft cushions with two paragraphs of context first. Clear is kind: the bad news should come before the explanation, not after.","task":"Write a 2-3 sentence message that leads with the bad news, then the path.","tips":["State the overrun in sentence one — don't make them wait for it.","The cushion delays the pain; it doesn't reduce it.","After the news, give the path: what sign-off is needed."],"focus":["clarity","impact"],"placeholder":"The project is $50K over budget and needs VP approval to continue —"},
    {"id":"hard-fin-early-02","level":"early","profession":"finance","title":"The clean 'no' to an expense","scenario":"A manager submitted a $600 client gift that policy prohibits. Your draft waffles — 'I'm not sure this might work, let me see' — leaving him hoping. Clear is kind: a clean no now saves him a week of false hope.","task":"Write a 2-3 sentence reply that says no plainly and explains the one reason.","tips":["Say no in the first sentence; don't leave a door open that's shut.","Give the single policy reason, not a lecture.","Offer the alternative if one exists — that's the kindness."],"focus":["clarity","impact"],"placeholder":"I can't approve this one — gifts over $250 aren't reimbursable under policy —"},
    {"id":"hard-fin-early-03","level":"early","profession":"finance","title":"Telling your manager you'll miss the deadline","scenario":"The reconciliation you own won't be done by the close deadline because a dependency slipped. Hiding it until the last minute is worse. You need to tell your manager now — clearly, with the impact and your plan.","task":"Write a 3-sentence message: the miss, the cause, your plan to limit the damage.","tips":["Lead with the miss, not the excuse.","State the impact on close plainly.","Bring a plan — a partial delivery, a workaround — not just the problem."],"focus":["clarity","structure"]},
    {"id":"hard-fin-early-04","level":"early","profession":"finance","title":"Behavior, impact, ask — the late submitter","scenario":"A budget owner has submitted late three months running, each time forcing you to rush the consolidation. You need to give feedback that changes it, using behavior → impact → ask, not vague irritation.","task":"Write a 3-sentence feedback message: the specific behavior, its impact on you, the specific ask.","tips":["Name the behavior factually — 'the last three submissions were 2+ days late.'","State the concrete impact — the rushed consolidation, the error risk.","End with a clear, specific ask, not a wish that it improves."],"focus":["clarity","impact"]},
    {"id":"hard-fin-early-05","level":"early","profession":"finance","title":"The overpayment you have to claw back","scenario":"A vendor was overpaid $4K due to your team's error and you need to ask for it back. It's awkward and it's your side's mistake. Clear and direct, owning the error, works better than a buried, hedged request.","task":"Write a 3-sentence message that owns the error and makes the clear ask for repayment.","tips":["Own the mistake plainly — it builds credibility for the ask.","State the amount and the specific request.","Make it easy — offer the mechanism for returning it."],"focus":["clarity","impact"]},
    {"id":"hard-fin-early-06","level":"early","profession":"finance","title":"Declining a colleague's shortcut","scenario":"A friendly colleague asks you to 'just push this through' without the required approval, framing it as a small favor. Saying yes creates a control breach. You need to decline without damaging the relationship.","task":"Write a 2-3 sentence reply that declines warmly but firmly and offers the right route.","tips":["Keep the warmth; hold the line.","Explain it's not personal — the control applies to everyone.","Offer to help him get the approval fast — the constructive no."],"focus":["clarity","audience"]},
    {"id":"hard-fin-early-07","level":"early","profession":"finance","title":"The error you have to report upward","scenario":"You discovered your own team posted a $30K entry to the wrong period, and leadership already saw the wrong number. You have to tell your manager. The instinct to bury it in qualifiers must yield to a clear, front-loaded disclosure.","task":"Write a 3-sentence message: what's wrong, the corrected impact, what you're doing about it.","tips":["Disclose the error in sentence one — delay compounds it.","State the corrected number so she can act.","Show the fix and the prevention in the same breath."],"focus":["clarity","impact"],"placeholder":"I need to flag an error we made: a $30K entry hit April instead of May — the corrected April figure is —"},
    {"id":"hard-fin-early-08","level":"early","profession":"finance","title":"Telling a team their tool is being cut","scenario":"Budget pressure means a tool a small team relies on is being discontinued. They'll be unhappy. The kind approach is direct: what's happening, when, and what the alternative is — not a vague 'changes are coming.'","task":"Write a 3-sentence announcement that delivers the cut clearly with the alternative.","tips":["Say what's ending and the date — no euphemisms.","Give the alternative in the same message.","Vague warnings breed more anxiety than the clear news does."],"focus":["clarity","audience"]},
    {"id":"hard-fin-early-09","level":"early","profession":"finance","title":"The 'your numbers are wrong' to a peer","scenario":"A colleague's report to leadership uses a figure you know is wrong, and it'll embarrass them if it goes out. You need to flag it privately, clearly, before the meeting — kindly, but without softening it into ambiguity.","task":"Write a 2-3 sentence private message that flags the error clearly and offers to help fix it.","tips":["Flag it privately and specifically — which number, why it's off.","Be direct enough that they can't miss it before the meeting.","Offer to help correct it — you're on their side."],"focus":["clarity","audience"]},
    {"id":"hard-fin-early-10","level":"early","profession":"finance","title":"Refusing to backdate","scenario":"A manager asks you to date an invoice approval earlier than it happened so it falls in this quarter. This is a clear line you can't cross. You need to refuse unambiguously while keeping it professional.","task":"Write a 2-3 sentence refusal that is clear on the line and offers the legitimate path.","tips":["Refuse without wobble — this isn't negotiable.","Name why plainly, without moralizing at him.","Offer the correct treatment so he has a path forward."],"focus":["clarity","impact"],"placeholder":"I can't backdate the approval — it has to carry the date it actually happened. What we can do instead —"},
    {"id":"hard-fin-early-11","level":"early","profession":"finance","title":"The disappointing forecast to leadership","scenario":"Your updated forecast shows the department will miss its savings target by $60K. Nobody wants to hear it. Clear is kind: state the miss, the cause, and the realistic new number, without hiding it in optimistic framing.","task":"Write a 3-sentence message that delivers the miss honestly with the revised target.","tips":["Lead with the revised number and the gap.","Give the honest cause, not a hopeful spin.","A realistic new target beats an aspirational one that also fails."],"focus":["clarity","precision"]},
    {"id":"hard-fin-early-12","level":"early","profession":"finance","title":"Feedback to someone more senior","scenario":"A senior manager keeps sending you data in an inconsistent format that costs you hours to clean. Giving upward feedback is uncomfortable but necessary. Use behavior → impact → ask, respectfully but clearly.","task":"Write a 3-sentence message that raises the issue with a senior person constructively.","tips":["Frame it as a small process fix, not a criticism of them.","State the behavior and the time cost factually.","Make the ask a simple, specific template or format."],"focus":["clarity","audience"]},
    {"id":"hard-fin-early-13","level":"early","profession":"finance","title":"The write-off nobody wants to approve","scenario":"A $12K receivable is uncollectible and needs to be written off, but the account owner keeps insisting it'll pay 'any day now.' You have to deliver the hard call that it's time to write it off, with the evidence.","task":"Write a 2-3 sentence message that delivers the write-off recommendation clearly with the basis.","tips":["State the recommendation directly — it's time to write it off.","Give the evidence that ends the wishful thinking — 180 days, no response.","Acknowledge the hope, then close it with facts."],"focus":["clarity","precision"]},
    {"id":"hard-fin-early-14","level":"early","profession":"finance","title":"Saying no to a rush request during close","scenario":"During close crunch, a manager wants a custom analysis by tomorrow that would derail your critical-path work. You have to say no, or rather 'not until Thursday,' clearly — without leaving him thinking maybe.","task":"Write a 2-3 sentence reply that declines the timing clearly and offers the real date.","tips":["Don't leave a false 'I'll try' hanging — give the real date.","Briefly say why — close is the priority this week.","A firm 'Thursday' serves him better than a vague 'maybe.'"],"focus":["clarity","impact"]},
    {"id":"hard-fin-early-15","level":"early","profession":"finance","title":"The uncomfortable audit finding to the owner","scenario":"The auditors flagged that a manager's team has been approving transactions above their authority limit. You have to relay this to the manager before the formal report. It's uncomfortable and it implicates his team.","task":"Write a 3-sentence message that delivers the finding factually and frames the remediation.","tips":["State the finding without softening it into deniability.","Keep it about the process gap, not the people's character.","Move quickly to remediation — that's the constructive frame."],"focus":["clarity","audience"]},
    {"id":"hard-fin-early-16","level":"early","profession":"finance","title":"Correcting a number leadership already used","scenario":"You realize a figure you provided, which the VP quoted in a board update, was overstated by $25K. The message is doubly hard — it's your error and it's already public. It must go out clearly and fast.","task":"Write a 3-sentence message that corrects the record, owns it, and states the right figure.","tips":["Speed matters — the wrong number is spreading.","Own the error cleanly; don't diffuse it into 'a discrepancy was noted.'","Give the correct figure prominently so the fix travels."],"focus":["clarity","impact"]},
    {"id":"hard-fin-early-17","level":"early","profession":"finance","title":"The 'this expense is being investigated' note","scenario":"A pattern of expenses on one card needs review and you must inform the cardholder their transactions are being examined, without accusing them or tipping into false reassurance. Clear, neutral, and factual is the only safe register.","task":"Write a 2-3 sentence message that informs neutrally without accusation or false comfort.","tips":["State the fact — a review is happening — plainly and neutrally.","Don't accuse and don't over-reassure; stay factual.","Say what you need from them and the timeline."],"focus":["clarity","audience"]},
    {"id":"hard-fin-early-18","level":"early","profession":"finance","title":"Declining to fund from another budget","scenario":"A manager whose budget is exhausted asks you to quietly charge his overspend to a different department's line. You have to refuse this clearly — it's miscoding — while not making him feel attacked for asking.","task":"Write a 2-3 sentence refusal that's clear on why and points to the legitimate option.","tips":["Refuse the miscoding directly — it has to hit the right cost center.","Explain briefly without implying bad intent.","Point to the real route — a budget transfer with approval."],"focus":["clarity","impact"],"placeholder":"I can't charge it to their line — it has to sit where the cost belongs. The clean way to do this is a budget transfer, which needs —"},
    {"id":"hard-fin-early-19","level":"early","profession":"finance","title":"Telling a colleague their request is out of scope","scenario":"A colleague keeps asking you for analyses that aren't your job and are eating your time. You need to draw a boundary clearly and kindly — declining the pattern, not just this one request.","task":"Write a 2-3 sentence message that declines the ongoing ask and redirects appropriately.","tips":["Address the pattern, not only today's request.","Be warm but clear about what you can and can't own.","Redirect to the right owner or channel."],"focus":["clarity","audience"]},
    {"id":"hard-fin-early-20","level":"early","profession":"finance","title":"The bad news with no silver lining","scenario":"You have to tell your manager that a $20K prepaid balance was actually a duplicate you should have caught months ago, and there's no recovery — it's a straight loss. There's no upside to offer. Deliver it cleanly without inventing false comfort.","task":"Write a 2-3 sentence message that delivers the loss honestly and states the prevention.","tips":["Don't manufacture a silver lining that isn't there.","State the loss and own the miss cleanly.","The forward-looking piece is the control that prevents a repeat."],"focus":["clarity","impact"]},
    {"id":"hard-fin-early-21","level":"early","profession":"finance","title":"Pushing back on your manager's number","scenario":"Your manager wants to present a savings figure you believe is overstated and won't survive scrutiny. You have to tell her, before the meeting, that the number is shaky — hard because it's her number and she's senior.","task":"Write a 2-3 sentence message that raises the concern clearly with the specific issue.","tips":["Raise it privately and early, framed as protecting her.","Point to the specific weakness the number won't survive.","Offer the defensible figure as the alternative."],"focus":["clarity","audience"]},
    {"id":"hard-fin-early-22","level":"early","profession":"finance","title":"The 'we can't reimburse this' to a new hire","scenario":"A new employee, three weeks in, submitted $400 of expenses that fall outside policy — a genuine misunderstanding, not abuse. You have to deny the claim clearly while keeping it a gentle teaching moment.","task":"Write a 2-3 sentence message that denies the claim clearly and teaches the rule warmly.","tips":["Be clear it can't be reimbursed — don't leave it ambiguous.","Keep the tone warm; it's a learning moment, not a violation.","Explain the rule so the next claim is right."],"focus":["clarity","audience"]},
    {"id":"hard-fin-early-23","level":"early","profession":"finance","title":"Reporting a colleague's error you found","scenario":"You found a material error in a report your colleague sent to the controller, and you have to raise it upward because it's already been acted on. It's hard because it exposes a peer's mistake, but silence is worse.","task":"Write a 2-3 sentence message to the controller that reports the error factually without throwing the colleague under the bus.","tips":["Focus on the error and its impact, not on blame.","State the correction and what needs to change downstream.","Keep it professional — the goal is the fix, not the fault."],"focus":["clarity","precision"]},
    {"id":"hard-fin-early-24","level":"early","profession":"finance","title":"The firm reminder after being ignored","scenario":"You've asked a department three times for their accrual data and been ignored, and now the close is at risk. The next message has to escalate the firmness clearly — polite but with a real consequence — without becoming hostile.","task":"Write a 2-3 sentence message that raises the firmness and states the consequence clearly.","tips":["Acknowledge this is the escalation — the tone should shift.","State the concrete consequence of continued silence.","Firm and clear is not the same as angry; stay professional."],"focus":["clarity","impact"],"placeholder":"This is my final request before I escalate: without your accrual data by 3pm today, I'll estimate your numbers and note the source —"},
    {"id":"hard-fin-early-25","level":"early","profession":"finance","title":"Admitting you gave wrong guidance","scenario":"You told a manager last week a purchase was within policy; it wasn't, and he's already committed to it. You have to admit your guidance was wrong and deliver the consequence, both hard, both necessary and fast.","task":"Write a 3-sentence message that owns the wrong guidance, states the consequence, and offers the path.","tips":["Own the error first — you gave the wrong steer.","State the consequence plainly — what it means for his purchase.","Offer whatever path exists to limit the damage."],"focus":["clarity","impact"]}
  ],
  "putting-it-together": [
    {"id":"together-fin-early-01","level":"early","profession":"finance","title":"The full month-end email","scenario":"Close is done and you owe the controller the wrap-up email. It needs everything: the headline (closed on day 4), the one open item, the two variances worth flagging, and the next-month heads-up — all structured, concise, and at her altitude.","task":"Write the complete 4-5 sentence close-summary email, integrating every skill.","tips":["Lead with the headline, then structure the rest into clear points.","Cut everything she doesn't need; keep the two variances that matter.","Match her altitude — she reports up, so give her forwardable lines."],"focus":["structure","concision"],"placeholder":"April closed on day 4. One item carries to May; two variances worth your attention:"},
    {"id":"together-fin-early-02","level":"early","profession":"finance","title":"Same message, three channels","scenario":"The budget freeze needs to reach 14 owners (email), the managers' Slack (one line), and be summarized aloud in tomorrow's standup (30 seconds). Same fact, three registers. You have to match each to its channel.","task":"Write all three versions: the email opener, the Slack line, and the spoken standup sentence.","tips":["Email: the rule, reason, and exception path.","Slack: the rule and a link — nothing more.","Standup: one spoken sentence anyone can repeat."],"focus":["audience","concision"]},
    {"id":"together-fin-early-03","level":"early","profession":"finance","title":"Edit like a reader","scenario":"You've drafted a dense 200-word variance explanation for the operations director. Before sending, you need to read it as she will — busy, skimming, looking for what she must act on — and cut it to what survives that read.","task":"Rewrite the 200-word draft as the ~60-word version a skimming reader actually needs.","tips":["Read it as the recipient, not the author.","Keep only what changes what she does.","The headline and the one action survive; the rest is backup."],"focus":["concision","audience"]},
    {"id":"together-fin-early-04","level":"early","profession":"finance","title":"The recommendation memo, end to end","scenario":"You're recommending the company drop an underused $15K/year software license. The memo needs a BLUF recommendation, the evidence, the pre-empted objection, and a clear ask — the whole toolkit in one short document.","task":"Write the complete 4-5 sentence memo integrating recommendation, evidence, objection, and ask.","tips":["Open with the recommendation, not the analysis.","One line of evidence, one pre-empted objection.","End with the specific decision you need and by when."],"focus":["structure","impact"],"placeholder":"Recommendation: drop the Insight Pro license and save $15K/year. Usage data shows 9 of 25 seats active last quarter —"},
    {"id":"together-fin-early-05","level":"early","profession":"finance","title":"The status update under real constraints","scenario":"Your manager wants the project's finance status in a Slack message she can read on her phone between meetings. It has to be complete enough to act on but short enough to read in ten seconds — every skill compressed.","task":"Write the phone-readable status: state, one risk, one ask, in three lines.","tips":["Three short lines, each doing one job.","Lead with green/yellow/red so she knows the state instantly.","The ask must be answerable with a one-word reply."],"focus":["concision","structure"]},
    {"id":"together-fin-early-06","level":"early","profession":"finance","title":"Translating and recommending at once","scenario":"You're writing to a non-finance director who needs to understand why her costs jumped AND decide whether to approve a fix. You must translate the cause into her terms, then recommend clearly — audience and presence together.","task":"Write a 3-4 sentence message that explains the cause plainly and ends with your recommendation.","tips":["Translate the accounting cause into her language first.","Then shift into a clear recommendation.","Two skills in one message — don't let the jargon or the hedging creep back."],"focus":["audience","impact"]},
    {"id":"together-fin-early-07","level":"early","profession":"finance","title":"The hard message, done fully","scenario":"You must tell a manager his project is over budget, that finance can't cover it, and that he needs to either cut scope or get VP approval — bad news, a clean no, and a path, all in one message at the right register.","task":"Write the complete 3-4 sentence message: front-loaded news, clean no, clear path.","tips":["Bad news first, then the boundary, then the path.","Don't cushion the no into ambiguity.","End on the two concrete choices he has."],"focus":["clarity","structure"]},
    {"id":"together-fin-early-08","level":"early","profession":"finance","title":"The 60-second verbal brief","scenario":"You have sixty seconds in the team meeting to brief on the quarter's spend. You need a signposted opening, one governing message, two supporting points, and a clean close — the whole spoken toolkit, out loud.","task":"Script the full 60-second brief: signpost, governing point, two supports, close.","tips":["Signpost the shape before diving in.","One governing message; two supports, no more.","Close on the takeaway, not a trailing 'so yeah.'"],"focus":["structure","impact"]},
    {"id":"together-fin-early-09","level":"early","profession":"finance","title":"The email you'd want to receive","scenario":"You're asking three departments for overdue data with a hard deadline. Write the email you'd actually want to receive in their shoes: clear ask, real deadline, easy to act on, respectful of their time — every principle applied.","task":"Write the complete request email, optimized for the recipient acting immediately.","tips":["Ask and deadline in the first sentence.","Make acting trivial — list exactly what you need.","Respect their time by being short; that's what earns the fast reply."],"focus":["clarity","audience"]},
    {"id":"together-fin-early-10","level":"early","profession":"finance","title":"From messy notes to clean summary","scenario":"After a budget meeting you have a page of scattered notes: decisions, action items, open questions, and asides, all jumbled. You need to turn it into a clean follow-up that everyone can act on — structure, concision, and clarity together.","task":"Write the follow-up: decisions made, actions with owners, open questions — three clean sections.","tips":["Group the mess into decisions, actions, and open questions.","Each action gets an owner and a date.","Cut the asides entirely — they weren't decisions."],"focus":["structure","concision"]},
    {"id":"together-fin-early-11","level":"early","profession":"finance","title":"The precise, persuasive flag","scenario":"You've spotted that discounting is quietly eroding margin and you want leadership to act. This needs precision (the exact numbers) and persuasion (concrete stakes, pre-empted objection) working together in one short flag.","task":"Write a 3-4 sentence flag that is both precisely evidenced and persuasively framed.","tips":["Anchor on the one telling number, precisely stated.","Make the stake concrete — what it's costing per quarter.","Pre-empt the 'but discounts drive volume' objection with data."],"focus":["precision","impact"]},
    {"id":"together-fin-early-12","level":"early","profession":"finance","title":"Answering the CFO's staffer completely","scenario":"The CFO's chief of staff asks a pointed question about travel spend in a thread that leadership reads. You need to answer the actual question first, at the right altitude, precisely, and with presence — under mild pressure, in writing that others see.","task":"Write the 2-3 sentence reply that answers directly, precisely, and at her altitude.","tips":["Answer the exact question in sentence one.","Give the precise figures she needs, not a data dump.","Own any judgment cleanly — leadership is reading."],"focus":["clarity","precision"]},
    {"id":"together-fin-early-13","level":"early","profession":"finance","title":"The one-pager for the VP","scenario":"Your manager asks you to draft a one-pager for the VP on consolidating banking relationships. It needs a BLUF recommendation, structured evidence, plain language, and a clear ask — a complete executive document from a junior analyst.","task":"Write the one-pager's opening: assertion-title, recommendation, and the three supporting points as headlines.","tips":["The title asserts the recommendation.","Three supporting headlines carry the argument on their own.","Executive-ready means the VP gets it from titles alone."],"focus":["structure","impact"],"placeholder":"Consolidate from four banks to two — saving $18K in annual fees and simplifying controls"},
    {"id":"together-fin-early-14","level":"early","profession":"finance","title":"The reforecast note to a team owner","scenario":"Revenue is soft and a team must cut discretionary spend 10%. Your note needs to lead with what changes for them, translate the reason plainly, deliver the hard part clearly, and stay respectful — several skills in one delicate message.","task":"Write the complete 3-4 sentence note, integrating audience-framing and the hard message.","tips":["Lead with their number and what counts as discretionary.","Explain the company reason briefly and plainly.","Deliver the cut clearly without spin, and offer help prioritizing."],"focus":["audience","clarity"]},
    {"id":"together-fin-early-15","level":"early","profession":"finance","title":"The variance thread that stays on the rails","scenario":"Your manager's quick Slack question about a $12K travel-expense variance has spiraled into a long thread — the department admin chimed in about a conference invoice, accounts payable flagged a possible duplicate receipt, and the original question is now buried. You've since confirmed the real cause: the conference was booked in March but hit April's ledger.","task":"Write the single consolidating message that states the cause, closes the open loops, and ends the thread.","tips":["Lead with the answer: a timing difference, not overspend.","Close each side-question in one clause (invoice legitimate, duplicate already reversed).","End with a clear 'unless you say otherwise, I'll note it as timing in the variance report' close."],"focus":["concision","structure"]},
    {"id":"together-fin-early-16","level":"early","profession":"finance","title":"The register shift mid-audience","scenario":"You're forwarding your technical reconciliation to your manager, who will forward it to the non-finance operations lead. You need a cover note that re-frames the technical work for the eventual non-finance reader — anticipating an audience two steps away.","task":"Write the cover note that translates your technical work for the reader your manager will forward it to.","tips":["Write for the final reader, not just your manager.","Give a forwardable plain-language summary on top.","Keep the technical detail below, clearly labeled as backup."],"focus":["audience","structure"]},
    {"id":"together-fin-early-17","level":"early","profession":"finance","title":"The complete variance walkthrough","scenario":"In the monthly review you present the department's variances aloud. You need PREP structure, precise numbers, a clear recommendation on the one action item, and the composure to handle the follow-up — the full spoken package.","task":"Script the 4-5 sentence walkthrough: point, the numbers, the recommended action, restated point.","tips":["Lead with the one-line verdict on the month.","Give only the numbers that support the verdict.","End on the one action and be ready for the follow-up."],"focus":["structure","precision"]},
    {"id":"together-fin-early-18","level":"early","profession":"finance","title":"The tight ask with full context available","scenario":"You need your manager's approval on a $9K correcting entry. The ask should be one clean line, but you also need the context ready if she asks. Structure it so the ask leads and the detail is there but subordinated.","task":"Write the message: the one-line ask up front, then the context clearly subordinated below.","tips":["The ask stands alone in the first line.","Context goes below, labeled, so it doesn't dilute the ask.","She can approve on the line or drill down — her choice, not forced."],"focus":["structure","concision"],"placeholder":"Approval needed: post a $9K correcting entry to fix the department miscoding? Context below if useful —"},
    {"id":"together-fin-early-19","level":"early","profession":"finance","title":"The proactive brief before you're asked","scenario":"You can see a cash pinch coming in three weeks from a tax payment colliding with payroll. Nobody's asked, but presence means bringing it forward — precisely quantified, clearly framed, with a recommended action — before it's a crisis.","task":"Write the proactive 3-4 sentence brief: the coming issue, the numbers, the recommended action.","tips":["Lead with the issue and its date — that creates the urgency.","Quantify the pinch precisely.","Bring the recommended action, not just the alarm."],"focus":["impact","precision"]},
    {"id":"together-fin-early-20","level":"early","profession":"finance","title":"The correction that rebuilds trust","scenario":"You sent a report with an error, someone caught it, and now you're issuing the correction. It needs to own the mistake cleanly, state the right numbers precisely, and show the prevention — turning a slip into a display of reliability.","task":"Write the complete correction: owning it, the corrected figures, the prevention, in 3-4 sentences.","tips":["Own it plainly — one line, no grovel.","State the corrected numbers so the fix travels.","Show the control you've added — that's what rebuilds trust."],"focus":["clarity","precision"]},
    {"id":"together-fin-early-21","level":"early","profession":"finance","title":"The end-to-end vendor recommendation","scenario":"You've analyzed three vendors and must recommend one to procurement. The handoff needs a clear recommendation, the deciding evidence, the pre-empted objection, and the risk flag — framed for what procurement will use, not your methodology.","task":"Write the 4-5 sentence handoff: recommendation, deciding evidence, objection answered, risk flagged.","tips":["Lead with the pick and the one deciding fact.","Give procurement leverage, not your spreadsheet tour.","Flag the one risk yourself before they find it."],"focus":["structure","impact"],"placeholder":"Recommend Vendor B: 12% cheaper at our volumes with same terms. The fair concern is their newer track record —"},
    {"id":"together-fin-early-22","level":"early","profession":"finance","title":"The all-hands finance line","scenario":"The comms lead needs one or two sentences on the quarter's finances for the company all-hands, understandable by everyone, accurate, and framed so it means something to a general audience — precision and audience together, in public.","task":"Write the 1-2 sentence all-hands finance line: accurate, jargon-free, meaningful to everyone.","tips":["Keep the numbers that matter; translate the rest.","Say why it matters to the room, plainly.","Accurate and accessible are both required — no spin, no jargon."],"focus":["audience","precision"],"placeholder":"We brought in $8.4M this quarter — 12% more than last year — and kept costs flat, which means —"},
    {"id":"together-fin-early-23","level":"early","profession":"finance","title":"The escalation with everything in place","scenario":"A department has ignored you for two weeks and the close now depends on it. You're escalating to your manager: the ask of her, the impact, the concise history, and the recommended action — structured so she can act in one read.","task":"Write the complete escalation: the ask, the impact, the one-line history, the recommended action.","tips":["Ask of your manager first — what you need her to do.","Impact second — what breaks without it.","Compress the history to one line; end on the recommended action."],"focus":["structure","impact"]},
    {"id":"together-fin-early-24","level":"early","profession":"finance","title":"The whole thing, halved","scenario":"You wrote a thorough, well-structured 150-word update covering the close, two variances, and a heads-up. Your manager asks for it at half the length without losing anything that matters — the final test of every skill at once.","task":"Rewrite the update at ~75 words, keeping every load-bearing fact and the structure.","tips":["Halving forces you to rank what's truly load-bearing.","Keep the structure even as you cut the words.","What survives the cut is what mattered; the rest was padding."],"focus":["concision","structure"]},
    {"id":"together-fin-early-25","level":"early","profession":"finance","title":"The message that does it all","scenario":"Your manager is out and you must send the controller a single email that reports close status, flags one real issue with a recommendation, translates it for a non-finance reader cc'd, and asks for one decision — every skill, one message, no second chance.","task":"Write the complete email integrating status, a recommended fix, plain-language framing, and a clear ask.","tips":["Lead with status, then the one issue and your recommendation.","Add a plain-language line for the cc'd non-finance reader.","End with the single decision you need and the deadline."],"focus":["structure","audience"],"placeholder":"Close is on track for day 5, with one issue needing a call:"}
  ]
};
